import type { Drill } from "./types";

// Operations executive / senior drills, keyed by module slug — 25 per module.
// Pitched at a VP Operations / COO-track leader: board strategy, capacity and
// automation investment cases, crisis communications, network redesigns,
// executive KPI reviews, workforce change, and major vendor negotiations.
// Merged into course.ts.
export const OPERATOR_SENIOR_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-ops-senior-01","level":"senior","profession":"operator","title":"The plant fire board update","scenario":"A fire shut down your largest plant last night. No injuries, sprinklers contained it, and you expect the main line back in nine days. Your draft to the board opens with a timeline of the night's events.","task":"Write a 2-3 sentence board update that leads with impact and recovery date.","tips":["Sentence one: what happened, who is safe, when you are back.","The chronology of the night is appendix material.","Board members forward the first sentence — make it complete."],"focus":["clarity","impact"],"placeholder":"Fire at the Columbus plant last night; no injuries, and the main line restarts in nine days."},
    {"id":"lead-ops-senior-02","level":"senior","profession":"operator","title":"The capex ask that hides its number","scenario":"You are asking the CEO to approve $42M for warehouse automation with a 3.1-year payback. Your draft memo spends two pages on labor market trends before the request appears.","task":"Write an opening paragraph (2-3 sentences) that states the ask, the number, and the payback first.","tips":["Lead with the decision you want: approve $42M.","Payback and headline benefit belong in the first breath.","Market context supports the ask; it is not the ask."],"focus":["structure","impact"],"placeholder":"I'm asking you to approve $42M for warehouse automation, with a 3.1-year payback."},
    {"id":"lead-ops-senior-03","level":"senior","profession":"operator","title":"The recall recommendation","scenario":"Quality has confirmed a seal defect in one production lot that could leak in the field. You believe a voluntary recall of that lot is the right call. Your note to the CEO currently walks through the investigation before stating your position.","task":"Write a 2-4 sentence note that leads with your recommendation to recall.","tips":["Your recommendation is the headline, not the conclusion.","Scope it precisely in the same breath: which lot, how many units.","Investigation detail follows for those who want it."],"focus":["clarity","impact"],"placeholder":"I recommend we voluntarily recall lot 4417 — roughly 18,000 units."},
    {"id":"lead-ops-senior-04","level":"senior","profession":"operator","title":"The weekly CEO email buried in metrics","scenario":"Your weekly operations email to the CEO opens with a table of fourteen KPIs. The real story this week: OTIF recovered to 96% after two bad months. The CEO has told you she reads these on her phone.","task":"Write the first two sentences of the email so the week's headline comes first.","tips":["Lead with the one thing that changed, not the dashboard.","A phone reader gets one screen — spend it on the story.","The table can live below or in an attachment."],"focus":["concision","audience"]},
    {"id":"lead-ops-senior-05","level":"senior","profession":"operator","title":"The retailer fine exposure","scenario":"Your largest retail customer will levy chargebacks — roughly $1.8M this quarter — because your fill rate dropped below their contract floor. You need to tell the CEO before the retailer's CEO does. Your draft starts with the history of the account.","task":"Write a 2-3 sentence heads-up that leads with the exposure and your fix.","tips":["First sentence: the number and the cause.","Second: what you are doing and when it is fixed.","The CEO should be able to repeat it accurately after one read."],"focus":["clarity","impact"],"placeholder":"Heads-up: we expect ~$1.8M in chargebacks from Target this quarter because fill rate fell below the 95% floor."},
    {"id":"lead-ops-senior-06","level":"senior","profession":"operator","title":"The ERP go/no-go","scenario":"The executive team meets in an hour to decide whether the ERP cutover proceeds this weekend. Testing cleared 94% of scenarios; the open items are cosmetic. You are the accountable executive and your slide currently opens with the testing methodology.","task":"Write your opening statement (1-2 sentences) that leads with your call.","tips":["State go or no-go in the first sentence.","Give the single strongest reason immediately after.","Methodology is for the Q&A, not the opening."],"focus":["clarity","structure"],"placeholder":"My call is go: 94% of test scenarios passed and the remaining items are cosmetic."},
    {"id":"lead-ops-senior-07","level":"senior","profession":"operator","title":"The DC closure memo opener","scenario":"Your network study concluded that closing the Memphis distribution center and expanding Louisville saves $11M a year with better service to 80% of customers. The decision memo you drafted opens with the study's history and scope.","task":"Rewrite the memo's first sentence to carry the recommendation and the headline benefit.","tips":["One sentence: close Memphis, expand Louisville, $11M and better service.","Decision-makers read openings; analysts read appendices.","Separate the ask (approve the plan) from the context (the study)."],"focus":["clarity","concision"]},
    {"id":"lead-ops-senior-08","level":"senior","profession":"operator","title":"The allocation call to sales","scenario":"A resin shortage means you can fill only 70% of next month's demand. You have decided to protect contracted customers first and cut spot orders. Your message to the sales leadership team currently opens by apologizing for the situation.","task":"Write a 2-3 sentence message that leads with the decision and the rule.","tips":["Lead with the allocation rule, plainly stated.","Sales needs something to act on, not an apology.","Numbers make the rule usable: 70%, contracted first."],"focus":["clarity","impact"],"placeholder":"We can fill 70% of April demand, and contracted customers come first."},
    {"id":"lead-ops-senior-09","level":"senior","profession":"operator","title":"The board pre-read cover note","scenario":"Your 30-page pre-read covers the quarter, the automation program, and a footprint decision. Only one item needs a board vote: the footprint plan. Your cover note currently summarizes all three equally.","task":"Write a cover note (2-3 sentences) that leads with the one decision the board must make.","tips":["Tell the board what you need from them in sentence one.","Distinguish 'for decision' from 'for information' explicitly.","Point to the page where the decision material starts."],"focus":["structure","audience"]},
    {"id":"lead-ops-senior-10","level":"senior","profession":"operator","title":"The union vote result","scenario":"The ratification vote just closed: the contract passed 68% to 32%, securing labor peace for three years. The CEO is boarding a flight in ten minutes. Your draft recaps the negotiation before giving the result.","task":"Write a 1-2 sentence message that leads with the outcome.","tips":["The vote result is the entire headline.","Add the one implication that matters: three years of stability.","Save the negotiation story for tomorrow."],"focus":["concision","clarity"],"placeholder":"Contract ratified, 68-32."},
    {"id":"lead-ops-senior-11","level":"senior","profession":"operator","title":"The safety incident call to the chair","scenario":"A contractor was seriously injured at your Reno facility two hours ago. He is stable in hospital, the area is secured, and OSHA has been notified. You must brief the board chair by phone and your notes start with the contractor firm's history.","task":"Write your first two spoken sentences, leading with what happened and the person's condition.","tips":["Person first: who was hurt and how they are doing.","Then containment: area secured, regulator notified.","Background on the contractor comes only if asked."],"focus":["clarity","structure"],"placeholder":"A contractor was seriously injured at Reno this morning; he's stable in hospital."},
    {"id":"lead-ops-senior-12","level":"senior","profession":"operator","title":"'Are we ready for peak?'","scenario":"The CEO asks you point-blank in staff meeting whether operations is ready for peak season. You are — with one exception: seasonal hiring in the Southeast is 200 heads short. Your instinct is to walk through the readiness checklist first.","task":"Give a 2-3 sentence spoken answer that leads with the verdict.","tips":["Answer the question first: yes, with one exception.","Name the exception and its fix immediately.","The checklist proves the verdict; it doesn't replace it."],"focus":["clarity","concision"],"placeholder":"Yes, with one exception: we're 200 seasonal heads short in the Southeast."},
    {"id":"lead-ops-senior-13","level":"senior","profession":"operator","title":"The vendor termination note","scenario":"After three failed corrective-action plans, you are terminating your secondary packaging supplier and moving volume to two qualified alternates. Your note to the exec team opens with eighteen months of history.","task":"Write a 2-3 sentence note that leads with the decision and the continuity plan.","tips":["Decision first: we are exiting this supplier.","Answer the reader's immediate fear — continuity — in sentence two.","History earns one clause, not three paragraphs."],"focus":["clarity","impact"]},
    {"id":"lead-ops-senior-14","level":"senior","profession":"operator","title":"The capex overrun heads-up","scenario":"The new packaging line is tracking $6.2M over its $28M budget, driven by steel prices and a redesigned conveyor. The CFO hates surprises at quarter close. Your draft email opens with the project's original justification.","task":"Write a heads-up to the CFO that puts the overrun number in the first sentence.","tips":["Lead with the number and the completion impact.","Two causes, one line each — no essay.","State what you want: absorb, re-approve, or descope."],"focus":["precision","clarity"],"placeholder":"The packaging line is tracking $6.2M over budget; I need 15 minutes to walk you through the options."},
    {"id":"lead-ops-senior-15","level":"senior","profession":"operator","title":"The mid-outage text","scenario":"Your order-management system has been down for 90 minutes and the CEO texts: 'status?'. You know the cause (a failed database failover), the fix is in progress, and orders will queue but not be lost.","task":"Write a text-message reply of at most two sentences that leads with what matters most.","tips":["Lead with impact and ETA, not the technical cause.","Say what is NOT at risk — no lost orders.","One text; she will call if she needs more."],"focus":["concision","impact"],"placeholder":"Orders are queuing, none lost; system back in ~1 hour."},
    {"id":"lead-ops-senior-16","level":"senior","profession":"operator","title":"The KPI review opening line","scenario":"You open the monthly executive KPI review. The story of the month: cost per unit fell 4% but on-time delivery slipped in the West, and those two facts are connected. Your current opener is 'let's go through the numbers.'","task":"Write an opening line that states the month's headline, connections included.","tips":["Name the story, not the agenda.","Connect the two facts — that's the insight only you can offer.","The room follows the meeting you frame in line one."],"focus":["structure","impact"]},
    {"id":"lead-ops-senior-17","level":"senior","profession":"operator","title":"The automation ROI answer","scenario":"A board member asks: 'What has the automation program actually returned so far?' The answer is $9.4M annualized against $31M invested, ahead of the original curve. You are tempted to start with the program's phases.","task":"Give a 1-2 sentence spoken answer that leads with the number.","tips":["Say the return in the first ten words.","Compare it to plan — 'ahead of curve' is the second beat.","Phases and detail wait for a follow-up question."],"focus":["precision","concision"],"placeholder":"$9.4M annualized against $31M invested — ahead of the original curve."},
    {"id":"lead-ops-senior-18","level":"senior","profession":"operator","title":"The hiring-freeze exception","scenario":"A company-wide hiring freeze is on, but losing your two open maintenance-planner roles would jeopardize the reliability program that underpins next year's cost targets. You are emailing the CEO for an exception.","task":"Write a 2-3 sentence email that leads with the specific exception you need.","tips":["Ask for exactly what you want: two roles, named function.","Tie it to a commitment the CEO already cares about.","Keep the justification to one sentence — offer detail on request."],"focus":["clarity","impact"]},
    {"id":"lead-ops-senior-19","level":"senior","profession":"operator","title":"The insurance recovery update","scenario":"Four months after the flood, the insurer has agreed to pay $23M of your $27M claim, with funds arriving next month. Your update to the CFO and CEO opens with a recap of the adjuster meetings.","task":"Write a 2-sentence update that leads with the settlement amount and timing.","tips":["The number and the date are the news.","Name the $4M gap and whether you are contesting it.","Adjuster process detail goes in the file, not the email."],"focus":["precision","concision"],"placeholder":"The insurer has agreed to $23M of our $27M claim, paying next month."},
    {"id":"lead-ops-senior-20","level":"senior","profession":"operator","title":"The site selection verdict","scenario":"After a nine-month study of four candidate sites for the new plant, your team recommends Greenville: best labor pool, strong incentives, rail access. Your presentation to the executive committee opens with the selection methodology.","task":"Write your opening statement (1-2 sentences) that leads with the pick and the top reason.","tips":["Name the winner in sentence one.","Give the single most decisive factor, not all three.","Methodology defends the pick under questioning — it doesn't open."],"focus":["clarity","structure"],"placeholder":"We recommend Greenville."},
    {"id":"lead-ops-senior-21","level":"senior","profession":"operator","title":"The customer-CEO escalation reply","scenario":"The CEO of your second-largest customer emailed your CEO overnight about repeated late shipments, and your CEO forwarded it to you with 'handle this.' Your reply draft opens with an explanation of carrier issues.","task":"Write the first two sentences of your reply to the customer CEO, leading with your commitment.","tips":["Lead with ownership and the specific commitment, dated.","Explanations read as excuses when they come first.","Match their altitude: CEO to executive, outcomes not logistics."],"focus":["audience","impact"]},
    {"id":"lead-ops-senior-22","level":"senior","profession":"operator","title":"The OT cyber incident status","scenario":"Ransomware touched the network segment that runs two plants' control systems. Both plants isolated and switched to manual operation; production is at 60% and no data left the building. You are briefing the executive team in five minutes.","task":"Write your opening 2 sentences, leading with containment and production status.","tips":["Lead with the two answers everyone needs: is it contained, are we producing.","Quantify production impact — 60%, not 'reduced.'","Forensics and attribution come later; don't speculate."],"focus":["clarity","precision"],"placeholder":"The incident is contained: both plants are isolated and running manual at 60% output."},
    {"id":"lead-ops-senior-23","level":"senior","profession":"operator","title":"The root-cause verdict","scenario":"Three weeks of investigation into the recurring line-3 stoppages found a single root cause: a firmware mismatch introduced in April's upgrade. Your findings email to the exec team pastes the investigation timeline first.","task":"Write a 2-3 sentence email that leads with the conclusion, then the evidence.","tips":["Conclusion first: one root cause, named plainly.","Say what the fix is and when it lands.","Investigation narrative is the attachment."],"focus":["clarity","structure"]},
    {"id":"lead-ops-senior-24","level":"senior","profession":"operator","title":"The retention-bonus ask","scenario":"The Memphis closure was announced, but you need forty key employees to stay through the nine-month wind-down or the transition fails. You are asking the CHRO to approve a retention package worth $2.1M. Your draft opens with closure logistics.","task":"Write a 2-3 sentence message that leads with the ask and what it protects.","tips":["The ask — $2.1M for forty people — goes first.","Frame what it buys: a controlled nine-month transition.","Logistics belong in the plan document, not the ask."],"focus":["clarity","impact"],"placeholder":"I need approval for a $2.1M retention package covering forty key Memphis employees."},
    {"id":"lead-ops-senior-25","level":"senior","profession":"operator","title":"The one-sentence inventory answer","scenario":"The CFO is prepping for the earnings call and asks you for a one-sentence answer to the likely analyst question: 'Why is inventory up 18%?' The truth: you deliberately built buffer stock ahead of a supplier transition.","task":"Write that one sentence so the conclusion — deliberate, temporary — comes first.","tips":["Lead with 'deliberate': it converts a red flag into a plan.","Name the driver and the unwind date in the same sentence.","One sentence means one sentence — make every word carry."],"focus":["concision","precision"],"placeholder":"Inventory is up by design: we built buffer stock ahead of a supplier transition and it unwinds by Q1."}
  ],
  "start-with-the-audience": [
    {"id":"audience-ops-senior-01","level":"senior","profession":"operator","title":"OEE for the board","scenario":"OEE at your flagship plant fell from 78% to 71%, and it matters enough to brief the board. Most directors have never run a plant; 'availability losses from unplanned downtime' means nothing to them.","task":"Write a 2-3 sentence explanation of the decline in terms of money and customer risk, no jargon.","tips":["Translate OEE into what the board governs: cost, capacity, customer promises.","One plain analogy beats three defined acronyms.","End with whether they should be worried and why."],"focus":["audience","clarity"],"placeholder":"Our flagship plant is producing 7% less than it should for the same cost —"},
    {"id":"audience-ops-senior-02","level":"senior","profession":"operator","title":"Automation news for the floor","scenario":"You are announcing a $40M automation program to the workforce of the plant that will receive it. The business case celebrates '30% labor productivity improvement' — words that read as job cuts to every person in the room.","task":"Write a 3-4 sentence announcement addressed to frontline employees, answering their real question first.","tips":["Their question is 'do I still have a job' — answer it before anything else.","Be truthful about what changes; spin gets discovered in a week.","Say what happens next and when they'll hear more."],"focus":["audience","impact"]},
    {"id":"audience-ops-senior-03","level":"senior","profession":"operator","title":"The recall letter customers can use","scenario":"You are drafting the customer letter for the seal-defect recall. Legal's draft says 'units manufactured within the affected date range may exhibit seal degradation under certain conditions.' A customer just wants to know: is mine affected, and what do I do?","task":"Write 2-3 sentences a customer can act on without calling the hotline.","tips":["Give them the check: where to find the lot code, which codes matter.","Then the action: stop using it, here's the free fix.","Reassure with facts (no injuries reported), not adjectives."],"focus":["audience","clarity"],"placeholder":"Check the four-digit code on the base of the unit: if it reads 4417, stop using it and"},
    {"id":"audience-ops-senior-04","level":"senior","profession":"operator","title":"The S&OP miss for sales leaders","scenario":"The demand plan sales signed up for missed by 22%, and the excess inventory now costs $3M a quarter. You are presenting this to the sales leadership team. Your draft is written in supply-chain language: forecast bias, safety stock, MAPE.","task":"Rewrite the core message in 2-3 sentences using the language of quota, customers, and deals.","tips":["Translate forecast bias into deals that didn't close versus deals promised.","Show what it costs them, not just you: constrained launches, discount pressure.","Invite a joint fix — you need their number, not their apology."],"focus":["audience","impact"]},
    {"id":"audience-ops-senior-05","level":"senior","profession":"operator","title":"Safety metrics for a new director","scenario":"A new board member with a banking background asks what 'TRIR of 1.8, down from 2.4' actually means. She is diligent and will remember whatever framing you give her for years.","task":"Write a 2-3 sentence explanation calibrated to a smart outsider.","tips":["Convert the rate into people: how many injuries, out of how many employees.","Give an external anchor — industry average — so she can judge it.","Skip the OSHA recordability rules entirely."],"focus":["audience","precision"],"placeholder":"It means 18 of every 1,000 employees had a recordable injury last year, down from 24 —"},
    {"id":"audience-ops-senior-06","level":"senior","profession":"operator","title":"The network redesign, CFO edition","scenario":"You are socializing the DC consolidation with the CFO before the board sees it. Your deck leads with service-level maps and transit-time improvements. The CFO thinks in cash, payback, and one-time costs.","task":"Write the 2-3 sentence version of the plan built for the CFO's frame.","tips":["Lead with net cash: annual savings, one-time cost, payback period.","Flag the P&L timing — restructuring charge now, savings later.","Service improvements are the second paragraph for this reader."],"focus":["audience","precision"]},
    {"id":"audience-ops-senior-07","level":"senior","profession":"operator","title":"The same redesign, for Memphis","scenario":"The same DC consolidation closes the Memphis site: 340 jobs over twelve months. You are writing the message that site leadership will read aloud to employees. The CFO framing — $11M in savings — would be an insult here.","task":"Write 3-4 sentences for the Memphis employees, leading with what happens to them.","tips":["Their stake first: timeline, severance, transfer options.","Say the honest reason in one sentence without corporate padding.","Commit to specifics they can verify: dates, named contacts, next meeting."],"focus":["audience","impact"]},
    {"id":"audience-ops-senior-08","level":"senior","profession":"operator","title":"Port congestion for the earnings call","scenario":"The CEO needs to explain on the earnings call why logistics costs rose 14%. Your input draft is pure operations: rolled sailings, detention and demurrage, chassis shortages. Analysts need cause, magnitude, duration.","task":"Write 2-3 sentences the CEO can say verbatim to investors.","tips":["Structure for the analyst: what happened, how big, how long it lasts.","One concrete detail adds credibility; five become noise.","Say what you're doing about it in the last sentence."],"focus":["audience","clarity"],"placeholder":"Ocean freight disruption added about $9M this quarter, and we expect it to ease by"},
    {"id":"audience-ops-senior-09","level":"senior","profession":"operator","title":"The quality escape, told to the buyer","scenario":"A supplier's faulty adhesive got through and 2% of units shipped to your biggest retail account may delaminate. You are calling their chief merchant. Your internal brief is full of CAPA language and supplier audits.","task":"Write your 3-sentence opening for that call in the buyer's terms: shoppers, shelves, returns.","tips":["Their stake: which SKUs, how many stores, what shoppers might see.","Bring the decision you've already made — pull, replace, credit — not a problem.","Save supplier-management detail for the follow-up memo."],"focus":["audience","impact"]},
    {"id":"audience-ops-senior-10","level":"senior","profession":"operator","title":"ERP downtime for customer service","scenario":"This weekend's ERP cutover freezes order entry from Friday 8pm to Sunday noon. The customer service team needs to know what to tell customers, and your IT-written draft talks about 'system migration windows and data reconciliation.'","task":"Write a 3-4 sentence briefing for CS agents, including one sentence they can say to customers.","tips":["Give agents the script, not the architecture.","Cover the three cases they'll face: new orders, order status, urgent changes.","Tell them where to escalate the exceptions."],"focus":["audience","clarity"]},
    {"id":"audience-ops-senior-11","level":"senior","profession":"operator","title":"'Capacity constrained' at pipeline review","scenario":"At the revenue pipeline review, you must tell sales leadership that the new product line can support only $30M of the $45M pipeline this year. Your operations framing — 'line 4 validation runs through Q3' — won't land.","task":"Write a 2-3 sentence statement in deal terms: what they can sell, from when, and what to do with the rest.","tips":["Give sales a number they can commit to customers.","Turn the constraint into sequencing: which deals to prioritize.","Offer the escalation path for must-win deals."],"focus":["audience","clarity"],"placeholder":"We can support $30M of the new-line pipeline this year, at full rate from July."},
    {"id":"audience-ops-senior-12","level":"senior","profession":"operator","title":"Productivity program, union room","scenario":"You are presenting the continuous-improvement program to union leadership before the floor hears about it. Your slides say 'eliminate waste and reduce cost per unit' — which this room hears as 'eliminate people.'","task":"Write your 3-sentence opening for this audience, addressing job security directly and honestly.","tips":["Say plainly what the program does and does not mean for headcount.","Anchor on what they value: safer work, less overtime chaos, site competitiveness.","Don't promise what you can't keep — this audience remembers."],"focus":["audience","impact"]},
    {"id":"audience-ops-senior-13","level":"senior","profession":"operator","title":"The corrective action, for the regulator","scenario":"The FDA investigator reviewing your corrective action plan reads hundreds of these. Your draft response is padded with commitment language — 'we take quality extremely seriously' — that regulators skim past looking for the concrete.","task":"Write 2-3 sentences describing one corrective action in the specific, verifiable terms a regulator wants.","tips":["What changed, who owns it, when it completed, how you verify it.","Delete every sentence about how seriously you take things.","Verifiable beats emphatic with this reader."],"focus":["audience","precision"]},
    {"id":"audience-ops-senior-14","level":"senior","profession":"operator","title":"Working capital for the sponsor","scenario":"Your PE sponsor's operating partner asks how you'll free up cash from operations. Your plan — SKU rationalization, supplier terms, consignment stock — is solid, but your draft describes activities, not cash.","task":"Write a 2-3 sentence summary in the sponsor's terms: dollars released, by when, at what risk.","tips":["Lead with the total cash number and timeline.","Sponsors price risk — name the one thing that could slip.","Activities are the how; cash is the what. Lead with the what."],"focus":["audience","precision"],"placeholder":"We'll release $22M of cash from working capital over three quarters:"},
    {"id":"audience-ops-senior-15","level":"senior","profession":"operator","title":"The holding statement","scenario":"A conveyor fire at your Ohio DC is on local news; footage shows smoke and fire trucks. Everyone is safe and the building is intact. Comms needs a holding statement in ten minutes, and it will be read by neighbors, employees' families, and customers.","task":"Write a 2-3 sentence public holding statement in plain language for a general audience.","tips":["People first, always: everyone is safe, say it first.","Say what happened in words a neighbor uses, not 'thermal event.'","Promise the next update and mean it."],"focus":["audience","clarity"]},
    {"id":"audience-ops-senior-16","level":"senior","profession":"operator","title":"Predictive maintenance for plant skeptics","scenario":"You are pitching the predictive-maintenance rollout to your ten plant managers, who have watched three corporate initiatives die in as many years. A vendor-style pitch about 'AI-driven asset intelligence' will lose the room in one slide.","task":"Write a 3-sentence opening in plant-floor terms: what changes on their shift, and what's in it for them.","tips":["Speak their pain: 3am calls, firefighting, blown weekend schedules.","One proof point from a plant they respect beats a vendor case study.","Say what you need from them — and what you're NOT asking for."],"focus":["audience","impact"]},
    {"id":"audience-ops-senior-17","level":"senior","profession":"operator","title":"Freight spike at the pricing committee","scenario":"Freight costs rose 23% and you need the pricing committee to pass some of it through. The committee thinks in margin and competitive dynamics, not lanes and fuel surcharges.","task":"Write a 2-3 sentence input framed in their terms: margin erosion and pass-through options.","tips":["Convert freight lanes into margin points lost per product family.","Give them options with numbers, not a description of the problem.","Note what competitors are doing — that's the language of this room."],"focus":["audience","precision"]},
    {"id":"audience-ops-senior-18","level":"senior","profession":"operator","title":"The new-COO introduction","scenario":"It's your first week as COO and you're writing the introduction message to all 4,000 operations employees. Your draft tries to speak to the board, your executive peers, and the floor at once — and lands with none of them.","task":"Write a 3-4 sentence introduction with the frontline workforce as the single primary audience.","tips":["Pick the primary reader and let the others overhear.","Say something checkable about yourself, not a values word-cloud.","Tell them the first thing you'll do — visits, listening, one commitment."],"focus":["audience","clarity"]},
    {"id":"audience-ops-senior-19","level":"senior","profession":"operator","title":"The cold-chain excursion, two audiences","scenario":"A refrigerated trailer failed and 40 pallets of product spent six hours above temperature. The QA team needs the technical facts; the customer needs to know whether their delivery is safe and on time. You have one hour and two messages to write.","task":"Write the 1-2 sentence core message for EACH audience, showing how the same fact changes shape.","tips":["QA gets temperatures, durations, and disposition protocol.","The customer gets safety, their order, and the replacement date.","Neither message should read like it was written for the other."],"focus":["audience","precision"]},
    {"id":"audience-ops-senior-20","level":"senior","profession":"operator","title":"Single points of failure, for the risk committee","scenario":"The board risk committee asked where operations is most fragile. Your honest answer: one plant makes 60% of gross margin, and one supplier is the sole source for a critical component. Your draft buries this in a 40-row risk register.","task":"Write a 2-3 sentence summary for the committee that names the two concentrations plainly.","tips":["Risk committees want the few things that could really hurt, ranked.","Quantify exposure in business terms: margin at risk, weeks to recover.","Pair each risk with its mitigation status — funded, planned, or unaddressed."],"focus":["audience","structure"],"placeholder":"Two concentrations dominate our risk: one plant produces 60% of gross margin, and"},
    {"id":"audience-ops-senior-21","level":"senior","profession":"operator","title":"Defending the buffer to the CFO","scenario":"The CFO wants the $18M safety-stock buffer cut in half to hit a year-end cash target. You believe halving it puts your two biggest accounts at risk during the supplier transition. You need to argue in his currency, not yours.","task":"Write a 2-3 sentence case for the buffer framed in financial exposure, not service levels.","tips":["Convert stockouts into his numbers: revenue at risk, chargeback exposure.","Offer a middle path with a date — cuts after the transition completes.","'Service level' is your word; 'revenue protection' is his."],"focus":["audience","impact"]},
    {"id":"audience-ops-senior-22","level":"senior","profession":"operator","title":"Why the customer left","scenario":"Your third-largest customer moved their volume to a competitor after a year of service failures, and the all-hands rumor mill is ahead of you. You owe the org an honest explanation that neither scapegoats a team nor sanitizes the loss.","task":"Write 3-4 sentences for the all-hands: what happened, why, and what changes.","tips":["Employees smell spin instantly — name the real reason.","Point at the system that failed, not a team.","End with the specific change, so the story has a second act."],"focus":["audience","impact"]},
    {"id":"audience-ops-senior-23","level":"senior","profession":"operator","title":"Automation ROI, for the CHRO","scenario":"The CHRO will co-present the automation program's people plan and asks you to explain the business case 'in people terms.' Your finance version — NPV, payback, cost per unit — doesn't mention a human being.","task":"Rewrite the case in 2-3 sentences centered on roles, redeployment, and skills.","tips":["Count roles, not FTEs: how many change, how many retrain, how many end.","Lead with what you're building for people, then what's being automated.","Keep the honesty of the finance version — just change the units."],"focus":["audience","clarity"]},
    {"id":"audience-ops-senior-24","level":"senior","profession":"operator","title":"The storm shutdown text","scenario":"A hurricane is forcing you to close three Gulf Coast sites tomorrow. The message goes by text to 1,200 hourly employees, many reading on old phones in a hurry. Corporate drafted four paragraphs with a policy link.","task":"Write the shutdown message in 2-3 short sentences an hourly worker can absorb in five seconds.","tips":["The three answers they need: closed when, paid or not, where updates come from.","Short words, short sentences — this is a text, not a memo.","Cut everything that isn't one of those three answers."],"focus":["audience","concision"],"placeholder":"All three Gulf sites are closed tomorrow. You will be paid for your scheduled shift."},
    {"id":"audience-ops-senior-25","level":"senior","profession":"operator","title":"Supplier bankruptcy, for the audit committee","scenario":"Your sole-source electronics supplier filed for bankruptcy protection. You have 11 weeks of stock and two alternates in qualification. The audit committee wants to understand exposure and controls, not procurement mechanics.","task":"Write a 2-3 sentence briefing for the committee in their frame: exposure, runway, mitigation.","tips":["Their questions: how bad could it get, how long is the runway, who's on it.","Quantify the gap between runway and qualification timeline honestly.","Committee members write notes — give them sentences worth copying."],"focus":["audience","precision"]}
  ],
  "structure-that-carries": [
    {"id":"structure-ops-senior-01","level":"senior","profession":"operator","title":"The three-bucket board strategy","scenario":"Your operations strategy for the board covers eleven initiatives across plants, network, and technology. In the room, eleven items become noise and directors lose the thread. You need one governing idea and no more than three groupings.","task":"Write the governing sentence plus the three bucket labels for your strategy.","tips":["One sentence answers 'what is the strategy' — everything hangs beneath it.","Force the eleven initiatives into at most three buckets.","Bucket labels should be outcomes, not activities."],"focus":["structure","clarity"],"placeholder":"Our operations strategy does one thing — make the network cheaper to run and harder to disrupt — through three moves:"},
    {"id":"structure-ops-senior-02","level":"senior","profession":"operator","title":"SCQA for the automation case","scenario":"You are opening the automation investment case to the executive committee. You have data, ROI, and a phased plan, but no frame — so the story starts in the middle. SCQA (situation, complication, question, answer) would set it up cleanly.","task":"Write a four-sentence SCQA opening for the automation case.","tips":["Situation: the stable truth everyone already accepts.","Complication: what changed that forces a decision now.","Question then answer: the decision, and your recommendation."],"focus":["structure","impact"]},
    {"id":"structure-ops-senior-03","level":"senior","profession":"operator","title":"PREP under a board question","scenario":"A director asks whether you can hit the cost target without cutting safety spend. You can, and you want to answer in a structure that lands: point, reason, example, point. Your instinct is to ramble through the budget.","task":"Give a spoken PREP answer (4 short sentences) to the director's question.","tips":["Point: yes, without touching safety — say it first.","Reason: where the savings actually come from.","Example then restate the point to close cleanly."],"focus":["structure","clarity"],"placeholder":"Yes — we hit the target without cutting a dollar of safety spend."},
    {"id":"structure-ops-senior-04","level":"senior","profession":"operator","title":"The messy KPI list","scenario":"Your executive KPI review lists nineteen metrics in the order the systems export them: safety next to freight cost next to attrition. The exec team can't see what's connected. The metrics need grouping into a logic the room can hold.","task":"Propose 3-4 group headings that reorganize the nineteen metrics into a story.","tips":["Group by what an executive steers: cost, service, risk, people.","Headings are the argument — make them mean something.","A metric belongs to one group; resist double-listing."],"focus":["structure","audience"]},
    {"id":"structure-ops-senior-05","level":"senior","profession":"operator","title":"The recall memo skeleton","scenario":"The recall decision memo to the CEO wanders: some cause, some scope, some cost, some legal, repeated twice. You need a skeleton the CEO can navigate — recommendation, then a fixed set of sections in a deliberate order.","task":"List the section headings for the memo, in order, each a short phrase.","tips":["Lead with the recommendation; everything else supports it.","Order sections by the reader's questions: what, how bad, what it costs, what next.","Parallel headings signal a mind in control."],"focus":["structure","clarity"]},
    {"id":"structure-ops-senior-06","level":"senior","profession":"operator","title":"One idea for the network redesign","scenario":"The network redesign deck has forty slides and no spine. Asked 'what's the one thing?', your team gives four answers. Before the board sees it, you need a single governing idea that every section serves.","task":"Write the one governing sentence for the network redesign.","tips":["If the deck proves one thing, what is it? Write that.","Test it: every section should be evidence for this sentence.","Cut anything that doesn't ladder up to it."],"focus":["structure","concision"],"placeholder":"We can serve customers faster and spend $11M less a year by running four regional hubs instead of seven."},
    {"id":"structure-ops-senior-07","level":"senior","profession":"operator","title":"SCQA for the crisis brief","scenario":"You are briefing the board mid-crisis on a supplier collapse. People are anxious and want reassurance, but you owe them a structure, not comfort. SCQA turns a scary situation into a decision the board can help with.","task":"Write a four-sentence SCQA brief on the supplier collapse.","tips":["Situation: what was stable and reliable until now.","Complication: the collapse and its clock.","Question and answer: the decision on the table and your plan."],"focus":["structure","impact"]},
    {"id":"structure-ops-senior-08","level":"senior","profession":"operator","title":"The capex request in three reasons","scenario":"You are justifying $60M of capacity investment. Your draft gives nine supporting arguments of equal weight, so none lands. The pyramid principle says pick the three strongest and subordinate the rest.","task":"State the ask, then the three reasons that carry it, each in one clause.","tips":["Rank your nine arguments; keep the top three as pillars.","Three reasons are memorable; nine are a blur.","The rest become evidence beneath the three, not peers to them."],"focus":["structure","precision"],"placeholder":"Approve $60M for line 5 for three reasons: we're capacity-capped, demand is contracted, and payback is under four years."},
    {"id":"structure-ops-senior-09","level":"senior","profession":"operator","title":"The town-hall spine","scenario":"You have thirty minutes for an operations town hall covering safety, the year's results, and the automation roadmap. Without a spine, it becomes three disconnected talks. You want one theme that threads all three.","task":"Write the connecting theme sentence and how each of the three topics ladders under it.","tips":["Find the theme that makes all three parts one talk.","State the theme, then one line placing each topic under it.","The audience should leave able to repeat the theme."],"focus":["structure","audience"]},
    {"id":"structure-ops-senior-10","level":"senior","profession":"operator","title":"Ordering the crisis update","scenario":"Your hourly outage update to the executive team currently lists whatever changed since last hour in random order. Under stress, the reader needs a fixed structure every time: status, impact, actions, next update.","task":"Write a four-line update template with those fixed headers, filled for a plausible outage.","tips":["Same four headers every hour builds trust under stress.","Status and impact first; actions and ETA second.","Consistency lets the reader find what they need instantly."],"focus":["structure","clarity"],"placeholder":"Status: OMS still down, 2h10m. Impact: orders queuing, none lost."},
    {"id":"structure-ops-senior-11","level":"senior","profession":"operator","title":"The vendor negotiation position paper","scenario":"You are aligning your executive team before a major supplier negotiation. Your draft mixes must-haves, nice-to-haves, and walk-away terms in one undifferentiated list. The team can't tell what's negotiable.","task":"Reorganize your position into three labeled tiers with one example term in each.","tips":["Three tiers: must-have, tradeable, walk-away.","The structure IS the strategy — it tells your team where to hold.","One clear example per tier beats a long unsorted list."],"focus":["structure","precision"]},
    {"id":"structure-ops-senior-12","level":"senior","profession":"operator","title":"The 'what's your plan' pyramid","scenario":"The CEO asks for your plan to recover on-time delivery. You have twelve actions. Delivered as a flat list, they sound like activity, not a plan. Grouped under a governing goal and three levers, they sound like command.","task":"Write the governing goal and three levers, with the twelve actions implied beneath.","tips":["Goal first: the number you'll hit and by when.","Three levers group the twelve actions into a shape.","The CEO remembers three levers; nobody remembers twelve actions."],"focus":["structure","clarity"],"placeholder":"We get on-time delivery back to 96% by Q3 through three levers: fix the constraint at line 3, add carrier capacity, and clean the demand signal."},
    {"id":"structure-ops-senior-13","level":"senior","profession":"operator","title":"SCQA for the footprint decision","scenario":"The footprint memo needs the board to approve closing two sites. You want them to feel the logic is inevitable by the time the recommendation appears. SCQA builds that runway.","task":"Write the four-sentence SCQA that makes the closure feel like the obvious answer.","tips":["Situation: the network you built for the demand you had.","Complication: how demand and cost have moved.","Question and answer land the closure as the natural conclusion."],"focus":["structure","impact"]},
    {"id":"structure-ops-senior-14","level":"senior","profession":"operator","title":"Grouping the risk register","scenario":"Your risk register for the board has 34 rows sorted alphabetically. The board can't see the shape of the risk. You need to collapse it into a few themes with the biggest exposures on top.","task":"Propose three risk themes and place the two or three biggest exposures under each.","tips":["Theme by nature of risk: supply, asset, workforce, cyber.","Rank within theme by exposure, not alphabet.","Three themes with the top exposures beats 34 equal rows."],"focus":["structure","precision"]},
    {"id":"structure-ops-senior-15","level":"senior","profession":"operator","title":"PREP on the automation skeptic","scenario":"At the exec table, the CFO says automation programs never deliver the promised savings. You disagree and have proof. PREP keeps your answer disciplined instead of defensive.","task":"Give a four-sentence PREP response: point, reason, example, point.","tips":["Point: ours is delivering — concede nothing false, claim nothing loose.","Reason: why this one is tracking when others didn't.","Example is your evidence; close by restating the point."],"focus":["structure","impact"],"placeholder":"This one is delivering — $9.4M annualized, ahead of plan."},
    {"id":"structure-ops-senior-16","level":"senior","profession":"operator","title":"The pre-read that navigates itself","scenario":"Your 30-page board pre-read has no map. Directors read it on planes and lose their place. A one-page structure at the front — governing message and three sections — would let them navigate.","task":"Write the front-page navigation: the governing message and three section descriptors.","tips":["Give the reader the whole shape before the detail.","Three sections, each a sentence saying what it decides or informs.","A reader who knows the structure reads faster and trusts more."],"focus":["structure","audience"]},
    {"id":"structure-ops-senior-17","level":"senior","profession":"operator","title":"The investment case in one pyramid","scenario":"Your predictive-maintenance investment case sprawls across reliability, safety, and cost with no hierarchy. The exec committee needs one claim at the top and three supports, not a swamp of benefits.","task":"Write the top-line claim and the three supporting pillars.","tips":["Top claim is the decision, quantified.","Three pillars — each a benefit category — carry the claim.","Everything else is evidence nested under a pillar."],"focus":["structure","precision"],"placeholder":"Predictive maintenance pays for itself in 18 months by cutting unplanned downtime, deferring $12M of capital, and reducing safety exposure."},
    {"id":"structure-ops-senior-18","level":"senior","profession":"operator","title":"The all-hands after the loss","scenario":"You are addressing 4,000 operations employees after losing a major customer. Your notes jump between blame, reassurance, and plans. The talk needs a clear arc: where we are, why, what we do now.","task":"Write the three-part arc as three heading sentences for the all-hands.","tips":["Three moves: honest present, honest cause, concrete future.","Each heading is a full sentence the audience could quote.","The arc carries the emotion; don't improvise the order."],"focus":["structure","audience"]},
    {"id":"structure-ops-senior-19","level":"senior","profession":"operator","title":"The KPI review that tells a story","scenario":"Your monthly KPI review reads the dashboard top to bottom, metric by metric, with no narrative. The exec team wants the story: what moved, why, what it means. Structure the review around insight, not the export order.","task":"Write the three story beats that should replace the metric-by-metric readout.","tips":["Beat one: the single most important change this month.","Beat two: the connection the numbers hide.","Beat three: what needs a decision — end on action."],"focus":["structure","impact"]},
    {"id":"structure-ops-senior-20","level":"senior","profession":"operator","title":"SCQA for the capacity ask","scenario":"Sales is screaming for capacity you don't have, and you need the board to fund it. SCQA frames the ask so the board sees the shortfall as their problem, not just operations'.","task":"Write a four-sentence SCQA leading to the capacity investment ask.","tips":["Situation: the demand the board has celebrated.","Complication: the capacity that can't meet it.","Question and answer: fund the line, or cap the growth."],"focus":["structure","impact"],"placeholder":"Situation: the board has guided to 20% volume growth. Complication: our lines top out at 12%."},
    {"id":"structure-ops-senior-21","level":"senior","profession":"operator","title":"The negotiation debrief structure","scenario":"You are debriefing the executive team after the first round of a major logistics contract negotiation. Your notes are a chronological blur of who said what. The team needs structure: where we stand, gaps, next moves.","task":"Write three headings that turn the chronological notes into a decision-ready debrief.","tips":["Structure by what the team must decide, not by timeline.","Where we agree, where the gaps are, what we do next.","Chronology is the appendix; the shape is the point."],"focus":["structure","clarity"]},
    {"id":"structure-ops-senior-22","level":"senior","profession":"operator","title":"The one governing idea for peak readiness","scenario":"Your peak-readiness review touches hiring, inventory, carriers, and systems. Presented as four parallel updates, it has no center. The exec team should leave with one governing judgment about readiness.","task":"Write the governing readiness statement, then one line placing each of the four areas under it.","tips":["Lead with the verdict: ready, or ready-except.","Each of the four areas is evidence for the verdict.","The verdict is what they'll remember; make it the spine."],"focus":["structure","clarity"],"placeholder":"We're ready for peak except in one place — and here's how the four workstreams stand against that."},
    {"id":"structure-ops-senior-23","level":"senior","profession":"operator","title":"PREP on the outage cause","scenario":"The CEO asks, in front of the exec team, why the outage happened. You know the cause and the fix. PREP keeps you from spiraling into a technical monologue.","task":"Give a four-sentence PREP answer on the outage cause and prevention.","tips":["Point: the single root cause, plainly named.","Reason: why it wasn't caught before.","Example of the fix, then restate the prevention point."],"focus":["structure","precision"],"placeholder":"Root cause was a failed database failover — one node, no automatic cutover."},
    {"id":"structure-ops-senior-24","level":"senior","profession":"operator","title":"The change narrative in three acts","scenario":"You are announcing a major reorganization of the operations org. Delivered as a list of new boxes and names, it feels arbitrary. A three-act structure — why change, what changes, what stays — makes it feel purposeful.","task":"Write the three act-headings for the reorganization announcement.","tips":["Act one: the why, tied to a goal people share.","Act two: what actually changes for them.","Act three: what stays steady — reassurance has a place in the structure."],"focus":["structure","audience"]},
    {"id":"structure-ops-senior-25","level":"senior","profession":"operator","title":"The board deck's governing message","scenario":"Your quarterly operations board deck has strong slides but no headline holding them together. A director asks 'so what's the one message?' and you don't have it ready. Every deck needs a governing message on the cover.","task":"Write the single governing message for this quarter's operations board deck.","tips":["One sentence that the whole deck exists to prove.","It should carry a verb and a stance, not just a topic.","If two people read the deck, they should name the same message."],"focus":["structure","concision"],"placeholder":"Operations delivered the cost target and bought resilience — and the footprint decision in front of you protects both."}
  ],
  "cut-to-the-bone": [
    {"id":"concise-ops-senior-01","level":"senior","profession":"operator","title":"The 300-word board summary","scenario":"Your operations section of the board pack runs 300 words and the chair asked everyone to hold summaries to 100. Half your draft is throat-clearing: 'It is worth noting that...', 'As we have discussed previously...'","task":"Cut the passage below to 100 words or fewer without losing a fact. (Draft your tightened version.)","tips":["Delete every 'it is worth noting' and 'as discussed' — they carry nothing.","Keep every number; cut every adjective earning its keep by feel alone.","Read it aloud; if you run out of breath, cut more."],"focus":["concision","clarity"]},
    {"id":"concise-ops-senior-02","level":"senior","profession":"operator","title":"Nominalizations in the recall memo","scenario":"Your recall memo is heavy with nominalizations: 'the implementation of a containment of the affected inventory was undertaken.' Buried inside is a simple action. The CEO wants verbs, not noun-clouds.","task":"Rewrite the sentence as a direct verb-driven statement.","tips":["Find the buried verb — 'contain' — and let it lead.","Name the actor: who did what.","One strong verb replaces three nouns and a helper."],"focus":["concision","clarity"],"placeholder":"We contained the affected inventory."},
    {"id":"concise-ops-senior-03","level":"senior","profession":"operator","title":"Hedges in the capex ask","scenario":"Your $42M automation ask hedges itself into weakness: 'we believe this could potentially deliver savings that may be in the region of...'. The CEO reads it as you not believing your own case.","task":"Rewrite the hedged sentence with the estimate stated plainly, hedges removed.","tips":["'Could potentially may' is three hedges doing one job badly — pick zero.","State the number and own the range: 'about $14M a year.'","Confidence in the writing signals confidence in the plan."],"focus":["concision","precision"],"placeholder":"This delivers about $14M a year in savings."},
    {"id":"concise-ops-senior-04","level":"senior","profession":"operator","title":"The redundant pairs","scenario":"Your executive update is full of redundant pairs: 'plan and prepare', 'each and every', 'true and accurate', 'future plans'. They pad the word count and dull the read. The exec team wants signal.","task":"Rewrite the sentence below cutting all redundant pairs to single words. (Use your own padded sentence.)","tips":["Each redundant pair is one idea wearing two coats — remove one.","'Future plans' — plans are always future; drop the modifier.","Precision reads as competence; padding reads as filler."],"focus":["concision","precision"]},
    {"id":"concise-ops-senior-05","level":"senior","profession":"operator","title":"Halve the outage post-mortem intro","scenario":"The outage post-mortem opens with two paragraphs restating what everyone lived through last week. The exec team was there; they want cause and prevention, not a recap. The intro can lose half its length.","task":"Cut the recap intro to two sentences that set up the analysis.","tips":["Assume the reader knows what happened — they were there.","Two sentences: what broke, how long. Then move to why.","Every recap sentence you keep delays the point they need."],"focus":["concision","clarity"],"placeholder":"OMS was down 3h12m on the 14th; roughly 4,000 orders queued and none were lost."},
    {"id":"concise-ops-senior-06","level":"senior","profession":"operator","title":"The meta-commentary cut","scenario":"Your negotiation brief keeps narrating itself: 'In this section, I will outline...', 'Before I get to the recommendation, let me first...'. The exec team doesn't need the tour; they need the content.","task":"Rewrite the opening removing all meta-commentary, going straight to the substance.","tips":["Delete 'in this section I will' — just say the thing.","'Before I get to X, let me...' means: get to X.","The reader wants the meal, not the menu narration."],"focus":["concision","clarity"]},
    {"id":"concise-ops-senior-07","level":"senior","profession":"operator","title":"The one-line status","scenario":"The CEO texts asking for a plant-restart status. Your draft reply is five sentences covering crew, permits, testing, and timeline. On a phone, that's a wall. She needs one line, detail on request.","task":"Compress the five-sentence status into a single sentence.","tips":["Pick the one fact she needs: the restart time.","Everything else is available if she asks.","One line respects her screen and her time."],"focus":["concision","impact"],"placeholder":"Main line restarts Thursday 6am; crew and permits are set."},
    {"id":"concise-ops-senior-08","level":"senior","profession":"operator","title":"Filler in the town-hall open","scenario":"Your town-hall opening warms up for ninety seconds: 'Thanks everyone for being here, I know you're all busy, before we dive in I just want to say...'. Four thousand people are waiting for the point.","task":"Rewrite the opening to reach your first real sentence in under fifteen words.","tips":["Cut the gratitude preamble to nothing or one clause.","'Before we dive in' is a sign you haven't dived in — dive.","The first real sentence should carry weight, not politeness."],"focus":["concision","impact"]},
    {"id":"concise-ops-senior-09","level":"senior","profession":"operator","title":"The bloated risk sentence","scenario":"One sentence in your risk brief runs forty words with three subordinate clauses about a single supplier concentration. The audit committee lost the thread by the comma. It needs to become two crisp sentences.","task":"Break the overloaded sentence into two clear ones.","tips":["One idea per sentence; the forty-word sentence holds three.","Split at the natural seams — the clauses want to be sentences.","Shorter sentences read as more certain."],"focus":["concision","clarity"]},
    {"id":"concise-ops-senior-10","level":"senior","profession":"operator","title":"Trim the vendor email","scenario":"Your email pushing back on a supplier's price increase runs four paragraphs, three of them relationship pleasantries. The one paragraph that matters — your counter — is buried. Trim to the counter plus one line of context.","task":"Cut the email to three sentences: context, counter, next step.","tips":["Pleasantries are one line, not three paragraphs.","Lead them to your number fast; that's why you're writing.","End with the concrete next step, not a warm wish."],"focus":["concision","impact"]},
    {"id":"concise-ops-senior-11","level":"senior","profession":"operator","title":"The qualifier pile-up","scenario":"Your assessment of peak readiness is smothered in qualifiers: 'generally speaking, for the most part, in most cases, broadly, we are largely on track.' The CEO can't tell if you're confident or not.","task":"Rewrite the assessment stating your confidence level once, plainly.","tips":["Five qualifiers cancel each other out — keep at most one.","If there's a real exception, name it; don't blanket-hedge.","'On track, with one exception' beats 'broadly, largely on track.'"],"focus":["concision","precision"],"placeholder":"We're ready, with one exception: Southeast seasonal hiring."},
    {"id":"concise-ops-senior-12","level":"senior","profession":"operator","title":"The passive-voice fog","scenario":"Your incident summary is written entirely in the passive: 'errors were made, the failover was not triggered, delays were experienced.' No one owns anything and the CEO can't tell who acts. Rewrite in the active voice.","task":"Rewrite the passive sentences as active, naming the actor.","tips":["Passive hides the actor; the CEO wants to know who and what.","'The failover didn't trigger' beats 'the failover was not triggered.'","Active voice is shorter and more accountable."],"focus":["concision","clarity"]},
    {"id":"concise-ops-senior-13","level":"senior","profession":"operator","title":"Cut the caveats from the forecast","scenario":"Your capacity forecast to the board is buried under caveats about assumptions, methodology, and data limitations. By the time the number appears, the board distrusts it. Give the number cleanly, caveats in a footnote.","task":"Rewrite so the forecast number leads and only the one material caveat remains.","tips":["Lead with the number; caveats follow, if at all.","Keep the single caveat that would change the decision.","A page of caveats reads as a lack of conviction."],"focus":["concision","precision"],"placeholder":"We can support 14 million units next year, assuming line 5 lands on schedule."},
    {"id":"concise-ops-senior-14","level":"senior","profession":"operator","title":"The over-explained slide title","scenario":"A slide in your board deck is titled 'Analysis of the Various Factors Contributing to the Observed Variance in On-Time Delivery Performance Across the Network.' Nobody reads a title that long. It should be the takeaway, in a phrase.","task":"Rewrite the slide title as a short takeaway sentence or phrase.","tips":["The title should state the point, not describe the analysis.","'On-time slipped in the West; here's why' beats a noun-parade.","If the title is a sentence with a verb, even better."],"focus":["concision","impact"],"placeholder":"On-time delivery slipped 4 points — all of it in the West."},
    {"id":"concise-ops-senior-15","level":"senior","profession":"operator","title":"The three-word intensifiers","scenario":"Your update leans on empty intensifiers: 'extremely significant', 'absolutely critical', 'hugely important', 'very substantial.' Everything is maximal, so nothing stands out. The exec team tunes out the volume.","task":"Rewrite the passage replacing intensifiers with facts. (Use your own inflated sentence.)","tips":["'Extremely significant' means nothing — a number means something.","Replace 'hugely important' with the stake it points to.","When everything is critical, nothing is; reserve the word."],"focus":["concision","precision"]},
    {"id":"concise-ops-senior-16","level":"senior","profession":"operator","title":"Halve the CAPA response","scenario":"Your corrective-action response to the regulator restates the finding three times before the fix. The investigator wants what changed, not repeated acknowledgment. Cut the restatement and lead with the action.","task":"Cut the response to two sentences: the action taken and how it's verified.","tips":["State the finding once, if at all — they wrote it.","Lead with what you changed and who owns it.","Verification is the sentence a regulator underlines."],"focus":["concision","precision"]},
    {"id":"concise-ops-senior-17","level":"senior","profession":"operator","title":"The email that buries the ask","scenario":"Your email to the CHRO asking for a retention-package approval spends four sentences on background before the request. She reads two hundred emails a day. The ask should arrive in the first line.","task":"Rewrite so the approval ask is the first sentence and the email is three sentences total.","tips":["Front-load the ask; background follows only if needed.","Three sentences: ask, why it matters, what you need from her.","A buried ask often goes unanswered."],"focus":["concision","impact"],"placeholder":"I need your approval on a $2.1M retention package for forty key Memphis staff."},
    {"id":"concise-ops-senior-18","level":"senior","profession":"operator","title":"The list that should be a sentence","scenario":"Your update presents five bullet points that are really one idea broken up for no reason. The fragmentation makes a simple point look complicated. Collapse them into one clean sentence.","task":"Rewrite the five fragmented bullets as a single sentence.","tips":["Bullets should carry distinct ideas, not fragments of one.","One flowing sentence can be clearer than five stubs.","If the bullets share a verb, they're one thought."],"focus":["concision","structure"]},
    {"id":"concise-ops-senior-19","level":"senior","profession":"operator","title":"The over-qualified 'no'","scenario":"You are declining a plant manager's request for extra capex, but your response wraps the 'no' in so much cushioning that he thinks it's a 'maybe.' Clarity is kindness here; the no should be findable.","task":"Rewrite the response so the 'no' is clear and the reason is one sentence.","tips":["Say no plainly; the cushioning creates false hope.","One sentence of reason respects him more than three of padding.","Offer the path, if there is one, in a single line."],"focus":["concision","clarity"],"placeholder":"I can't fund this in the current cycle."},
    {"id":"concise-ops-senior-20","level":"senior","profession":"operator","title":"Trim the earnings-call input","scenario":"The CEO asked for a two-sentence input on why logistics costs rose. Your draft is a paragraph with lane detail and surcharge names. On an earnings call, that's a liability. Cut to exactly what an analyst needs.","task":"Cut the paragraph to two sentences the CEO can say verbatim.","tips":["Analysts need cause, size, duration — not lane names.","Two sentences means two; the CEO won't read a third.","One vivid detail is fine; five is operational noise."],"focus":["concision","audience"],"placeholder":"Ocean freight disruption added about $9M this quarter; we expect it to ease by Q3."},
    {"id":"concise-ops-senior-21","level":"senior","profession":"operator","title":"The bloated commitment language","scenario":"Your customer-recovery letter is full of commitment padding: 'we are fully committed to and dedicated to ensuring that we consistently deliver.' The customer wants a date, not devotion. Replace the padding with a specific promise.","task":"Rewrite the padded commitment as one concrete, dated promise.","tips":["Devotion words are free and worthless; a date costs something.","'We'll be at 98% fill by March 1' beats any commitment phrase.","Specificity is the only credible form of commitment."],"focus":["concision","precision"],"placeholder":"You'll see fill rate back above 98% by March 1, and I'll send you weekly numbers until then."},
    {"id":"concise-ops-senior-22","level":"senior","profession":"operator","title":"The redundant 'in order to'","scenario":"Your strategy memo says 'in order to' eleven times, 'due to the fact that' four times, and 'at this point in time' twice. Each is a fat phrase hiding a small word. Trim them all.","task":"Rewrite the sentence below replacing every fat phrase with its short form. (Use your own.)","tips":["'In order to' is 'to'; 'due to the fact that' is 'because.'","'At this point in time' is 'now.' Say it.","Fat phrases add words, not meaning — cut them all."],"focus":["concision","clarity"]},
    {"id":"concise-ops-senior-23","level":"senior","profession":"operator","title":"The slide that says nothing","scenario":"A slide in your automation deck reads 'We are on a journey to leverage synergies and drive operational excellence across the enterprise.' It's pure filler. The board wants a claim they can test.","task":"Replace the empty slide sentence with a concrete, testable claim.","tips":["Delete 'journey', 'leverage', 'synergies', 'excellence' — all of them.","State something a skeptic could check: a number, a date, a result.","If nobody could disagree with it, it says nothing."],"focus":["concision","precision"],"placeholder":"Automation has cut cost per unit 6% at the two pilot plants."},
    {"id":"concise-ops-senior-24","level":"senior","profession":"operator","title":"The over-worded shutdown notice","scenario":"Your storm-shutdown notice to 1,200 hourly workers runs four paragraphs with a policy link. On a phone, in a rush, that's unreadable. It needs to say three things in three short sentences.","task":"Cut the notice to three short sentences: closed when, pay, where to check.","tips":["Three answers, three sentences, short words.","Drop the policy link into the last line, not the middle.","A worker should absorb it in one glance."],"focus":["concision","audience"],"placeholder":"All three Gulf sites are closed tomorrow. You'll be paid for your scheduled shift."},
    {"id":"concise-ops-senior-25","level":"senior","profession":"operator","title":"The final read-aloud test","scenario":"Your board narrative for the footprint decision is 500 words and technically complete, but sludgy. You'll read it aloud in the meeting. Every sentence you stumble on is a sentence to cut or split.","task":"Take your two densest sentences and rewrite each so they read cleanly aloud.","tips":["If you can't say it in one breath, it's too long.","Split at the point where you'd naturally pause.","Reading aloud exposes what the eye forgives."],"focus":["concision","clarity"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-ops-senior-01","level":"senior","profession":"operator","title":"'Significantly improved' to the board","scenario":"Your board slide says throughput 'significantly improved' this quarter. A director asks what 'significantly' means and you don't have the number to hand. Vague intensifiers invite exactly this exposure.","task":"Rewrite the claim with a specific number and baseline.","tips":["Replace 'significantly' with the percentage and the from-to.","Name the period and the baseline so it's checkable.","Numbers pre-empt the follow-up question; vagueness invites it."],"focus":["precision","clarity"],"placeholder":"Throughput rose 9% this quarter, from 41,000 to 44,700 units a day."},
    {"id":"precision-ops-senior-02","level":"senior","profession":"operator","title":"So what for the OEE number","scenario":"Your KPI review states OEE improved from 71% to 76%. True, but you left it as a fact with no meaning. The exec team needs the insight: what that five points buys the business.","task":"Add the 'so what': translate the 5-point OEE gain into a business outcome.","tips":["Data alone isn't insight — say what it means for capacity or cost.","Convert points into units, dollars, or customer promises kept.","End with whether it's enough or more is needed."],"focus":["precision","impact"],"placeholder":"OEE rose from 71% to 76% — that's 3,000 more units a day without new capital, enough to clear the West backlog."},
    {"id":"precision-ops-senior-03","level":"senior","profession":"operator","title":"The skeptic test on the savings claim","scenario":"You're claiming $14M in annual automation savings to the CFO, who will attack the number. Right now it's a round figure with no build. A skeptic will ask where it comes from and you need the components ready.","task":"State the $14M with its two or three biggest components, each quantified.","tips":["Break the round number into its real sources.","Name the assumption most likely to be challenged, and defend it.","A number that survives the skeptic is a number the CFO funds."],"focus":["precision","structure"],"placeholder":"The $14M is $9M in direct labor, $3M in scrap reduction, and $2M in avoided overtime."},
    {"id":"precision-ops-senior-04","level":"senior","profession":"operator","title":"Dates, not 'soon'","scenario":"Your restart update says the line will be back 'soon' and the backlog cleared 'shortly.' The CEO needs to commit to customers and can't with your adverbs. Replace them with dates.","task":"Rewrite the update replacing every vague time word with a specific date.","tips":["'Soon' and 'shortly' are unusable for planning — give dates.","If you're not sure, give a date with a confidence, not a fog.","A committed date is a promise; an adverb is an evasion."],"focus":["precision","clarity"],"placeholder":"The line restarts Thursday; the backlog clears by the 22nd."},
    {"id":"precision-ops-senior-05","level":"senior","profession":"operator","title":"The 'now what' the data implies","scenario":"Your safety report shows recordable injuries clustered on night shifts at two plants. You've stated the what and even the so-what, but stopped short of the now-what. The board wants the action the data demands.","task":"State the finding, its meaning, and the specific action in three sentences (what, so what, now what).","tips":["The finding: where and when injuries cluster.","The meaning: what that pattern points to.","The action: what changes, owned by whom, by when."],"focus":["precision","structure"]},
    {"id":"precision-ops-senior-06","level":"senior","profession":"operator","title":"'A lot of' inventory","scenario":"Your update tells the CFO there's 'a lot of' excess inventory tying up cash. He can't act on 'a lot.' The number, the cash, and the driver need to be exact.","task":"Rewrite with the inventory figure, the cash impact, and the cause.","tips":["'A lot' is invisible to a finance mind — quantify it.","Tie units to dollars — that's the CFO's currency.","Name the cause so the number becomes a plan."],"focus":["precision","impact"],"placeholder":"We're carrying $6M of excess finished goods — 40 days over target — from the Q2 demand miss."},
    {"id":"precision-ops-senior-07","level":"senior","profession":"operator","title":"The evidence behind 'on track'","scenario":"You told the board the automation program is 'on track.' A director asks against what. You have milestones and spend data but described it in feel, not fact. Ground the claim in evidence.","task":"Restate 'on track' with two concrete evidence points (milestone and spend).","tips":["'On track' needs a track — name the plan you're measuring against.","One schedule fact, one financial fact.","Evidence turns an assertion into a report."],"focus":["precision","structure"],"placeholder":"On track: four of five phases live, and spend is $31M against a $33M budget."},
    {"id":"precision-ops-senior-08","level":"senior","profession":"operator","title":"The recall scope, precisely","scenario":"Your recall note says 'a number of units may be affected.' Legal, the CEO, and the customer all need the exact scope: which lot, how many units, what percentage of them are actually at risk. Vagueness here is dangerous.","task":"State the recall scope with lot, unit count, and estimated defect rate.","tips":["Precision limits liability and panic — name the exact lot.","Give the unit count and the share genuinely at risk.","A precise scope is a smaller, more manageable problem."],"focus":["precision","clarity"],"placeholder":"Lot 4417, roughly 18,000 units, of which we estimate 2% carry the seal defect."},
    {"id":"precision-ops-senior-09","level":"senior","profession":"operator","title":"'Better service' quantified","scenario":"Your network redesign promises 'better service to customers.' The board wants to know how much better and to whom. Convert the promise into a measurable service claim.","task":"Rewrite 'better service' as a specific, measurable improvement.","tips":["'Better' is unfalsifiable — pick the metric that moves.","Say by how much and for what share of customers.","A measurable promise is one you can be held to — that's the point."],"focus":["precision","audience"],"placeholder":"Next-day delivery coverage rises from 62% to 80% of customers."},
    {"id":"precision-ops-senior-10","level":"senior","profession":"operator","title":"The one insight from ten charts","scenario":"Your KPI deck has ten charts and no conclusion. The exec team is drowning in trends. Your job is to extract the single insight the data supports and lead with it.","task":"Write the one-sentence insight that the ten charts collectively point to.","tips":["Charts are evidence; the insight is the verdict they support.","Say the connection the individual charts hide.","If you can't name one insight, the data isn't ready to present."],"focus":["precision","structure"],"placeholder":"Cost per unit fell because volume rose — not because we got more efficient, which is the risk if volume dips."},
    {"id":"precision-ops-senior-11","level":"senior","profession":"operator","title":"'Most' of the fleet","scenario":"Your capex case says 'most of the fleet is past its useful life.' The board asks how many and how far past. 'Most' won't fund anything. Give counts and ages.","task":"Rewrite with the exact count and the age profile of the aged assets.","tips":["'Most' hides the real number — state it.","Give the age against the standard so 'past life' means something.","Precise aging is what justifies the replacement spend."],"focus":["precision","impact"],"placeholder":"31 of 44 forklifts are past their 7-year service life, averaging 9.5 years."},
    {"id":"precision-ops-senior-12","level":"senior","profession":"operator","title":"The confidence interval the CFO wants","scenario":"You give the CFO a single-point capacity forecast of 14M units. He asks how confident you are. A point estimate with no range hides the risk he's pricing. Give the range and the swing factor.","task":"Restate the forecast as a range with the key variable that drives it.","tips":["A single number implies false certainty — give the band.","Name the one variable that moves the range most.","A stated range is more credible than a false point."],"focus":["precision","structure"],"placeholder":"13.2 to 14.8 million units, with line 5's ramp timing the biggest swing factor."},
    {"id":"precision-ops-senior-13","level":"senior","profession":"operator","title":"'Improved reliability' to the board","scenario":"Your maintenance program report claims 'reliability has improved.' The board can't govern a vibe. Convert reliability into the metric that matters: unplanned downtime.","task":"Restate the reliability claim as a specific downtime reduction.","tips":["Pick the reliability metric the board recognizes — downtime hours.","Give the from-to and the period.","One hard metric beats the word 'reliability.'"],"focus":["precision","clarity"],"placeholder":"Unplanned downtime fell 34%, from 210 hours a quarter to 138."},
    {"id":"precision-ops-senior-14","level":"senior","profession":"operator","title":"The skeptic test on payback","scenario":"You claim a 3.1-year payback on the warehouse automation. The CFO will probe the assumptions: labor rate, uptime, volume. If any is optimistic, the payback moves. Prepare the number to survive scrutiny.","task":"State the payback and the single assumption most likely to be challenged, with your defense.","tips":["Know which assumption is softest before the CFO finds it.","Show the payback's sensitivity to that one variable.","A defended number earns trust; an unexamined one loses it."],"focus":["precision","impact"]},
    {"id":"precision-ops-senior-15","level":"senior","profession":"operator","title":"'Around' the wrong number","scenario":"Your chargeback exposure note says 'around $2M.' Finance found it's $1.8M. The rounding cost you credibility. Give the actual figure and note the basis.","task":"Restate the exposure with the precise figure and how it was derived.","tips":["Round only when the precision doesn't exist — here it does.","State the basis: contract terms times the shortfall.","A precise number signals you've done the work."],"focus":["precision","clarity"],"placeholder":"Chargeback exposure is $1.8M this quarter — the contract's 2% penalty on $90M of below-floor shipments."},
    {"id":"precision-ops-senior-16","level":"senior","profession":"operator","title":"Evidence for the vendor's fault","scenario":"You're telling the exec team the packaging defect is the supplier's fault, not yours. That's a strong claim; it needs evidence, not assertion. Cite the specific proof before the supplier disputes it.","task":"State the fault claim backed by two specific evidence points.","tips":["A blame claim without evidence is just an opinion.","Cite the test result and the traceability record.","Evidence you can produce is evidence the supplier can't wave away."],"focus":["precision","structure"]},
    {"id":"precision-ops-senior-17","level":"senior","profession":"operator","title":"'High demand' from the field","scenario":"Sales says demand is 'high' and wants capacity. You need to convert 'high' into a number you can plan against before committing capital. Push the vague signal into a forecast.","task":"Rewrite the demand statement as a quantified forecast with a confidence note.","tips":["'High' can't be scheduled — turn it into units and a period.","State the confidence and what would firm it up.","Capital decisions need numbers, not adjectives."],"focus":["precision","clarity"],"placeholder":"Sales projects 2.4M units next year, up 18%, though only 60% is contracted."},
    {"id":"precision-ops-senior-18","level":"senior","profession":"operator","title":"The now-what on attrition","scenario":"Your workforce report shows maintenance-tech attrition hit 22%, well above target. You've flagged the number but not the response. The CHRO wants the specific action the data demands.","task":"State the attrition figure, its consequence, and your specific intervention (what, so what, now what).","tips":["What: the rate and where it's concentrated.","So what: what it costs — reliability, overtime, knowledge loss.","Now what: the named action and its owner."],"focus":["precision","structure"],"placeholder":"Maintenance-tech attrition is 22%, double target and concentrated in two plants; it's driving the overtime spike and reliability risk, so we're launching a retention adjustment and a shift-schedule fix by month-end."},
    {"id":"precision-ops-senior-19","level":"senior","profession":"operator","title":"'Substantial' capex overrun","scenario":"You told the CFO the packaging line has a 'substantial' overrun. He wants the number, the drivers, and the completion impact — not an adjective. Replace it with the facts.","task":"Rewrite with the overrun amount, the two main causes, and the schedule impact.","tips":["'Substantial' is a hedge — give the dollar figure.","Two causes, quantified, not narrated.","Say whether the date moves; that's what he'll ask next."],"focus":["precision","impact"],"placeholder":"$6.2M over the $28M budget — $4M from steel, $2.2M from the conveyor redesign — with no impact to the go-live date."},
    {"id":"precision-ops-senior-20","level":"senior","profession":"operator","title":"The insight in the freight data","scenario":"Freight cost per unit rose across every lane, but your analysis just lists the increases. The exec team needs the insight: is this rate inflation, mix, or your own inefficiency? Name the driver.","task":"State the one insight that explains the freight increase, backed by the data.","tips":["Don't just report the rise — diagnose it.","Distinguish external (rates) from internal (mix, routing).","The diagnosis determines the fix; lead with it."],"focus":["precision","structure"],"placeholder":"The 14% freight rise is 80% rate inflation and 20% our own routing — meaning most is market, but $1.8M is ours to fix."},
    {"id":"precision-ops-senior-21","level":"senior","profession":"operator","title":"The runway, to the week","scenario":"After the supplier bankruptcy, you tell the audit committee you have 'a few months' of stock. They need the exact runway against the qualification timeline to judge the risk. Give weeks, not months.","task":"State the inventory runway and the qualification timeline in weeks, with the gap named.","tips":["'A few months' hides whether there's a gap — give weeks.","Put runway and qualification side by side.","Name the gap explicitly; that's the risk they're assessing."],"focus":["precision","impact"],"placeholder":"We have 11 weeks of stock; the fastest alternate qualifies in 14 — a 3-week gap we're closing with an expedited protocol."},
    {"id":"precision-ops-senior-22","level":"senior","profession":"operator","title":"'Great progress' on the turnaround","scenario":"Your plant-turnaround update tells the CEO you're making 'great progress.' She's heard that before from failing turnarounds. Replace the reassurance with the three metrics that prove it.","task":"Restate 'great progress' with three specific metric improvements.","tips":["'Great progress' is what struggling projects say — give proof.","Pick the three metrics the turnaround was chartered to move.","From-to on each; feelings don't survive a turnaround review."],"focus":["precision","clarity"]},
    {"id":"precision-ops-senior-23","level":"senior","profession":"operator","title":"The evidence the outage won't recur","scenario":"After the outage, the CEO asks how you know it won't happen again. 'We've fixed it' isn't evidence. Cite the specific change and the test that proves it holds.","task":"State the prevention claim backed by the specific fix and the verification.","tips":["'We fixed it' is a hope; the test result is evidence.","Name what changed and how you proved it works.","Verification is what converts a claim into confidence."],"focus":["precision","structure"],"placeholder":"We've enabled automatic failover and tested it under load twice this week — both cutovers completed in under 30 seconds."},
    {"id":"precision-ops-senior-24","level":"senior","profession":"operator","title":"'Improved margins' from ops","scenario":"You're claiming operations 'improved margins' this year for the board narrative. Finance will want the basis points and the source. Convert the claim into the number and its driver.","task":"Restate the margin claim with basis points and the primary operational driver.","tips":["'Improved margins' needs a magnitude — basis points.","Attribute it to a specific operational lever.","A claim finance can trace is a claim finance defends for you."],"focus":["precision","impact"],"placeholder":"Operations added 120 basis points of gross margin, mostly from the 6% drop in cost per unit."},
    {"id":"precision-ops-senior-25","level":"senior","profession":"operator","title":"The one number for the earnings call","scenario":"The CFO wants a single operations metric to cite on the earnings call that proves the efficiency story. You have dozens. Pick the one that's precise, verifiable, and impressive, and state it cleanly.","task":"Write the one operations metric, precisely stated, for the earnings call.","tips":["Pick the metric that's both true and compelling.","State it precisely — analysts model on your exact words.","One clean, defensible number beats three fuzzy ones."],"focus":["precision","concision"],"placeholder":"We cut cost per unit 6% year over year while lifting volume 11%."}
  ],
  "executive-presence": [
    {"id":"presence-ops-senior-01","level":"senior","profession":"operator","title":"Own the footprint recommendation","scenario":"Your footprint memo lays out three options — status quo, consolidate two sites, consolidate four — with pros and cons for each, and stops. The board wants your call, not a menu. Neutral analysis reads as ducking the decision.","task":"Rewrite the close to state which option you recommend and why, owning it.","tips":["A menu without a recommendation pushes your job onto the board.","Name your pick and stand behind it in the first sentence.","Options are your analysis; the recommendation is your value."],"focus":["impact","clarity"],"placeholder":"I recommend consolidating two sites now — the four-site option saves more but risks service during the transition."},
    {"id":"presence-ops-senior-02","level":"senior","profession":"operator","title":"Signpost the board update","scenario":"Your board update runs eight minutes with no signposting, so directors can't tell where they are or what's coming. Presence includes structure the audience can hear. Add verbal signposts.","task":"Write the three signpost sentences that would frame your update (opening, transition, close).","tips":["Tell them the shape up front: 'three things — results, risk, one decision.'","Signal each transition so they never feel lost.","A clear close tells them what you need from them."],"focus":["structure","impact"]},
    {"id":"presence-ops-senior-03","level":"senior","profession":"operator","title":"Fact versus judgment on the outage","scenario":"Your outage brief blends what happened with what you think it means, so the exec team can't tell your data from your opinion. Presence means separating the two clearly. Restructure to divide fact from judgment.","task":"Write two labeled lines: one stating the facts, one stating your judgment.","tips":["Facts are what a camera saw; judgment is what you conclude.","Blending them lets others dispute your facts to dodge your judgment.","Separating them makes both harder to argue with."],"focus":["clarity","structure"],"placeholder":"Fact: the failover didn't trigger and we were down 3 hours. Judgment: this was a preventable gap in our runbook, and I own it."},
    {"id":"presence-ops-senior-04","level":"senior","profession":"operator","title":"The recommendation you're afraid to make","scenario":"You believe the company should exit a low-margin product line that ties up a whole plant, but it's the CEO's pet project. Your draft hints without recommending. Presence means saying the hard thing plainly.","task":"Write the recommendation in one clear sentence, owning the unpopular call.","tips":["Hedging on a hard call is more damaging than the call itself.","State it as a recommendation, not a question.","Your job is to give your best judgment, not to be liked."],"focus":["impact","clarity"],"placeholder":"I recommend we exit the coatings line — it consumes a full plant for 4% of margin."},
    {"id":"presence-ops-senior-05","level":"senior","profession":"operator","title":"Standing behind the number","scenario":"You present the automation savings estimate, then immediately undercut it: 'but of course these things are hard to predict.' The CFO now trusts neither you nor the number. Present it with ownership.","task":"Restate the estimate with conviction, acknowledging risk without disowning the number.","tips":["Own the number; then bound the risk — don't collapse the number.","'I'm confident in $14M; the swing factor is ramp speed' shows command.","Undercutting your own estimate invites everyone else to."],"focus":["impact","precision"],"placeholder":"I stand behind the $14M; the one thing that could move it is how fast the ramp lands."},
    {"id":"presence-ops-senior-06","level":"senior","profession":"operator","title":"The KPI review that leads","scenario":"You open the executive KPI review by narrating the dashboard, ceding the room's direction to whatever's on screen. Presence means setting the agenda, not following the export. Take command of the opening.","task":"Write an opening that asserts what the meeting is about and where you'll take it.","tips":["Frame the meeting; don't let the dashboard frame it.","Say the one thing that matters and the one decision you need.","Leading the room is presence; reading slides is not."],"focus":["impact","structure"]},
    {"id":"presence-ops-senior-07","level":"senior","profession":"operator","title":"'I recommend' versus 'we could'","scenario":"Your capex memo says the company 'could consider' automating the pick line. That's not a recommendation; it's a shrug. The CEO wants to know what you'd do. Convert the tentative language to ownership.","task":"Rewrite the 'we could consider' sentence as a first-person recommendation.","tips":["'We could consider' commits to nothing — 'I recommend' commits you.","First person signals accountability for the call.","The CEO funds recommendations, not considerations."],"focus":["impact","clarity"],"placeholder":"I recommend we automate the pick line this year."},
    {"id":"presence-ops-senior-08","level":"senior","profession":"operator","title":"The crisis briefing without panic","scenario":"You're briefing the board during the supplier collapse. Your draft language is anxious — 'this is really concerning', 'I'm worried.' The board needs steadiness from you. Restate with calm command while keeping honesty.","task":"Rewrite the opening to convey command and honesty without projecting panic.","tips":["Name the seriousness as a fact, not as your anxiety.","The board takes its temperature from yours — set it steady.","Calm plus a plan is presence; worry plus no plan is not."],"focus":["impact","audience"],"placeholder":"This is a serious disruption, and we have a plan and 11 weeks of runway to execute it."},
    {"id":"presence-ops-senior-09","level":"senior","profession":"operator","title":"Owning the miss","scenario":"On-time delivery missed target on your watch. Your draft to the exec team spreads the blame across carriers, demand, and IT. Presence means owning the outcome even when the causes are shared. Rewrite to take ownership.","task":"Write a 2-3 sentence statement that owns the miss while stating the fix.","tips":["Own the result; the cause-sharing reads as excuse-making.","'I own this and here's the fix' is stronger than any explanation.","Ownership buys you the room's trust for the recovery plan."],"focus":["impact","clarity"],"placeholder":"We missed the on-time target and I own it; here's what I'm changing."},
    {"id":"presence-ops-senior-10","level":"senior","profession":"operator","title":"The recommendation menu for the CEO","scenario":"The CEO asked what to do about the capacity shortfall. You send three options with even weighting and no lean. She wanted your judgment, not homework. Add a clear recommendation.","task":"Present the three options but lead with and justify your recommended one.","tips":["Give the options for context, then commit to one.","Justify the pick in a sentence — the trade-off you'd accept.","A leader shows the map and points to the road."],"focus":["impact","structure"]},
    {"id":"presence-ops-senior-11","level":"senior","profession":"operator","title":"Signposting the automation pitch","scenario":"Your automation investment pitch to the executive committee is dense and the audience keeps losing the thread. Presence includes making your structure audible. Add signposts that carry the room.","task":"Write the opening signpost that previews your three-part case.","tips":["Preview the structure: 'the problem, the plan, the payback.'","Numbered parts help the room track a dense argument.","Signposting is confidence made audible."],"focus":["structure","impact"],"placeholder":"I'll make this case in three parts: the capacity problem, the automation plan, and the payback."},
    {"id":"presence-ops-senior-12","level":"senior","profession":"operator","title":"Fact and judgment on the vendor","scenario":"You're recommending the board approve terminating a major supplier. Your memo mixes the factual failures with your judgment that they're unfixable. The board should see the evidence and your conclusion as distinct.","task":"Write two lines: the factual record, then your judgment and recommendation.","tips":["Lay out the facts the board can verify independently.","Then state your judgment — that they won't recover — as yours.","Separation lets the board trust the facts and weigh your call."],"focus":["clarity","impact"]},
    {"id":"presence-ops-senior-13","level":"senior","profession":"operator","title":"The confident 'I don't know yet'","scenario":"Mid-crisis, the board chair asks the total financial impact of the outage. You genuinely don't know yet. Presence isn't pretending — it's owning the gap with command and a path.","task":"Write a 2-sentence answer that owns not knowing while showing command.","tips":["'I don't know yet' with a date beats a made-up number.","Say when you'll know and how you'll get there.","Composure about uncertainty is its own form of presence."],"focus":["impact","clarity"],"placeholder":"I don't have the full financial impact yet — I'll have a firm number by Friday once claims and lost-order data are in."},
    {"id":"presence-ops-senior-14","level":"senior","profession":"operator","title":"The strong close","scenario":"Your board presentation on the network redesign trails off into 'so, yeah, that's the plan, happy to take questions.' A weak close undercuts a strong case. Presence means landing the ask cleanly.","task":"Write a strong closing that restates the recommendation and the specific ask.","tips":["End on the decision you need, not a mumble.","Restate the recommendation so the last thing they hear is your call.","A clean 'I'm asking the board to approve X' lands the presence."],"focus":["impact","clarity"],"placeholder":"I'm asking the board to approve the four-hub redesign today, so we can start the transition in Q3."},
    {"id":"presence-ops-senior-15","level":"senior","profession":"operator","title":"Not deferring the hard call","scenario":"The exec team is split on whether to recall a borderline lot. As the accountable operations executive, you keep saying 'it depends what everyone thinks.' Presence means making the call you're paid to make.","task":"Write your decision statement, owning the call rather than deferring to consensus.","tips":["Consensus-seeking on a safety call is abdication.","State your decision and take responsibility for it.","The room wants a leader, not a poll."],"focus":["impact","clarity"],"placeholder":"My call is to recall the lot; if we're debating a leak that could reach a customer, we recall."},
    {"id":"presence-ops-senior-16","level":"senior","profession":"operator","title":"The board Q&A stance","scenario":"In board Q&A a director challenges your capacity plan aggressively. Your instinct is to fold or over-explain. Presence means holding your ground with evidence, not ego. Draft your response.","task":"Write a 2-3 sentence response that holds your position with evidence, not defensiveness.","tips":["Acknowledge the challenge, then stand on the evidence.","Don't retreat from a sound position under pressure.","Firm and evidenced beats either defensive or capitulating."],"focus":["impact","precision"]},
    {"id":"presence-ops-senior-17","level":"senior","profession":"operator","title":"Owning the automation risk","scenario":"You're recommending the $42M automation program. A director asks about the risk of disruption during cutover. Downplaying it damages your credibility; owning it with a mitigation shows command.","task":"Write a 2-3 sentence answer that names the real risk and owns the mitigation.","tips":["Name the biggest risk before they do — it disarms the room.","Pair it immediately with your mitigation.","Owning risk with a plan is more presence than denying it."],"focus":["impact","precision"],"placeholder":"The real risk is cutover disruption; we're mitigating it by phasing the lines and keeping the old process live as backup for 30 days."},
    {"id":"presence-ops-senior-18","level":"senior","profession":"operator","title":"The all-hands that commands","scenario":"After the customer loss, you address 4,000 employees. Your draft is apologetic and small. The org needs to see steadiness and direction from you, not contrition. Rewrite the opening with presence.","task":"Write an opening that acknowledges the loss but leads with steadiness and direction.","tips":["Acknowledge honestly, then pivot to command and forward motion.","The org reads its confidence off your posture.","Lead them somewhere; don't just apologize."],"focus":["impact","audience"]},
    {"id":"presence-ops-senior-19","level":"senior","profession":"operator","title":"Recommending against the CEO's instinct","scenario":"The CEO wants to accelerate the automation timeline; you believe it's too fast and risks a botched cutover. Presence means telling her your real view, respectfully and clearly, not just agreeing.","task":"Write a 2-3 sentence recommendation that disagrees with the CEO's instinct, owning your view.","tips":["Respectful disagreement is presence; silent agreement is not.","State your view and the specific risk of the faster path.","Offer the alternative you'd stand behind."],"focus":["impact","clarity"],"placeholder":"I'd counsel against accelerating — the faster timeline raises real cutover risk, and I'd rather protect service than save two months."},
    {"id":"presence-ops-senior-20","level":"senior","profession":"operator","title":"The neutral menu on vendor selection","scenario":"You're presenting two shortlisted logistics partners to the exec committee with a balanced scorecard and no lean. They want your recommendation. A scorecard without a call is analysis, not leadership.","task":"State which partner you recommend and the single decisive reason.","tips":["The scorecard informs; your recommendation decides.","Name the one factor that tipped it for you.","Committees approve recommendations faster than they resolve ties."],"focus":["impact","clarity"],"placeholder":"I recommend Ryder — both scored close, but their Southeast network coverage is the difference that matters for us."},
    {"id":"presence-ops-senior-21","level":"senior","profession":"operator","title":"Judgment on the KPI trend","scenario":"Your KPI review shows cost per unit falling but you present it flatly, letting the room draw its own conclusion. Presence means offering your judgment on what the trend means and whether it holds.","task":"State the trend as fact, then add your judgment on whether it's sustainable.","tips":["Report the number, then say what you make of it.","Your judgment on durability is the value only you can add.","Flag the risk to the trend before someone else does."],"focus":["impact","precision"],"placeholder":"Cost per unit is down 6% — but my read is that half is volume-driven and would reverse if demand softens."},
    {"id":"presence-ops-senior-22","level":"senior","profession":"operator","title":"The composed answer to a blindside","scenario":"In the board meeting, a director surfaces a plant safety issue you weren't briefed on. You feel caught out. Presence means staying composed, owning the gap, and committing to follow up — not scrambling.","task":"Write a 2-sentence composed response to the blindside question.","tips":["Don't fake an answer you don't have — composure is the presence here.","Own that you'll get the facts and come back with a date.","Steadiness under a blindside is more memorable than the answer."],"focus":["impact","clarity"],"placeholder":"I don't have the detail on that in front of me, and I want to give you the accurate picture — I'll have it to the board by end of day."},
    {"id":"presence-ops-senior-23","level":"senior","profession":"operator","title":"Owning the trade-off","scenario":"Your capacity plan can protect either cost or service this year, not both, and you've chosen service. Rather than pretend there's no trade-off, presence means naming it and owning the choice.","task":"Write a 2-3 sentence statement that names the trade-off and owns your choice.","tips":["Pretending there's no trade-off insults the room's intelligence.","Name what you're giving up and why the choice is right.","Owning a hard trade-off is more credible than promising both."],"focus":["impact","clarity"],"placeholder":"We can protect cost or service this year, not both — and I've chosen service, because losing the two big accounts costs more than the overtime."},
    {"id":"presence-ops-senior-24","level":"senior","profession":"operator","title":"The recommendation under incomplete data","scenario":"The CEO needs a footprint decision now, but your data is 80% complete. You could hide behind 'we need more analysis' or make the call. Presence means recommending on the evidence you have, flagging the uncertainty.","task":"Write a recommendation that commits despite incomplete data, naming the uncertainty honestly.","tips":["'We need more analysis' can be a way to avoid deciding.","Recommend on what you know; flag what you don't.","Deciding under uncertainty with eyes open is executive presence."],"focus":["impact","precision"],"placeholder":"On the evidence we have, I recommend Greenville; the one open item is the incentive package, which I'll confirm won't change the ranking."},
    {"id":"presence-ops-senior-25","level":"senior","profession":"operator","title":"The single voice for operations","scenario":"In the executive meeting, operations comes across as three managers with three views. As COO, presence means being the single, clear voice for operations' position. Draft the unified statement you'd deliver.","task":"Write a 2-3 sentence statement that speaks for operations with one clear position.","tips":["Speak as the function's single voice, not a committee.","State operations' position and what it needs, plainly.","One clear voice from operations carries more weight than three."],"focus":["impact","clarity"]}
  ],
  "answering-under-pressure": [
    {"id":"pressure-ops-senior-01","level":"senior","profession":"operator","title":"'Will this recall hit earnings?'","scenario":"In the board meeting a director asks flatly whether the recall will hit this quarter's earnings. You want to talk about the great job the team did containing it. But that's not the question.","task":"Answer the earnings question directly first, in 2 sentences, then add context.","tips":["Answer the actual question before the story you'd rather tell.","Give the number or the range, then how you're managing it.","Dodging into 'the team did great' reads as evasion."],"focus":["clarity","impact"],"placeholder":"Yes — roughly $4M this quarter, mostly the replacement units and logistics; we're offsetting about half through the year."},
    {"id":"pressure-ops-senior-02","level":"senior","profession":"operator","title":"The CFO's pushback on payback","scenario":"You present a 3.1-year payback and the CFO snaps that your last three cases all slipped. Defensiveness will sink you. Answer the challenge with the specific reason this one is different.","task":"Write a 2-3 sentence response that handles the pushback with specifics, not defensiveness.","tips":["Don't argue the premise emotionally — engage it with facts.","Name the concrete difference this time (contracted volume, proven tech).","Specifics defuse skepticism; protest amplifies it."],"focus":["impact","precision"],"placeholder":"Fair challenge — the difference here is the volume is contracted, not forecast, so the payback doesn't depend on demand we might not get."},
    {"id":"pressure-ops-senior-03","level":"senior","profession":"operator","title":"The honest 'I don't know' on root cause","scenario":"Two hours into the outage the CEO asks what caused it. You have a hypothesis but no confirmation. Guessing risks being wrong on the record; stonewalling frustrates her. Give an honest answer with a path.","task":"Write a 2-sentence answer that's honest about the uncertainty and gives a path to the answer.","tips":["Distinguish what you know from what you suspect.","Commit to when you'll have the confirmed cause.","'Here's my hypothesis, confirming by X' beats a false certainty."],"focus":["clarity","precision"],"placeholder":"My working theory is a failover failure, but I won't confirm root cause until the logs are analyzed — I'll have it by 4pm."},
    {"id":"pressure-ops-senior-04","level":"senior","profession":"operator","title":"'Why didn't you see this coming?'","scenario":"After the supplier bankruptcy, a board member asks pointedly why you didn't see it coming. There's a defensive answer and an honest one. The honest one — partial visibility, a specific blind spot — serves you better.","task":"Write a 2-3 sentence answer that addresses the question honestly without either grovelling or deflecting.","tips":["Answer whether you could have seen it — honestly.","Name the specific limit of your visibility, not a vague excuse.","Then pivot to what you're changing so it improves."],"focus":["clarity","impact"]},
    {"id":"pressure-ops-senior-05","level":"senior","profession":"operator","title":"The loaded question from sales","scenario":"In the S&OP meeting the sales VP asks, 'So operations is fine losing us the deal?' The framing is a trap. Answer the real underlying question — can we support the deal — not the accusation.","task":"Write a 2-3 sentence response that reframes to the real question and answers it.","tips":["Don't accept the loaded framing; name the real question.","Answer whether and how the deal can be supported.","Reframe calmly — taking the bait escalates."],"focus":["clarity","audience"],"placeholder":"We're not fine losing the deal — the real question is what we can commit to, and here's what we can support and by when."},
    {"id":"pressure-ops-senior-06","level":"senior","profession":"operator","title":"'Is the plant safe?' — yes or no","scenario":"After the contractor injury, a director asks directly: is the plant safe to keep running? You want to explain the investigation. But this is a yes/no question that deserves a yes/no lead.","task":"Answer yes or no in the first word, then justify in 2 sentences.","tips":["A safety question deserves a direct verdict first.","Lead with yes or no; then the basis for it.","Burying the verdict in process reads as hiding something."],"focus":["clarity","impact"],"placeholder":"Yes — the area is secured, the cause is isolated, and the rest of the plant was never affected."},
    {"id":"pressure-ops-senior-07","level":"senior","profession":"operator","title":"The CEO's 'why is this so expensive?'","scenario":"The CEO challenges the automation capex as too rich compared to a competitor's rumored program. You could get defensive about the comparison. Instead, answer the cost question with the specific drivers.","task":"Write a 2-3 sentence answer that addresses the cost directly with its real drivers.","tips":["Engage the number, don't dispute the comparison you can't verify.","Name what drives your cost that may not drive theirs.","Facts about your own case beat speculation about theirs."],"focus":["precision","impact"]},
    {"id":"pressure-ops-senior-08","level":"senior","profession":"operator","title":"'Can you guarantee no more outages?'","scenario":"After the ERP outage, the audit committee asks if you can guarantee it won't happen again. You can't honestly guarantee zero. Answer the real intent — have you reduced the risk materially — without overpromising.","task":"Write a 2-3 sentence answer that's honest about 'guarantee' while conveying real risk reduction.","tips":["Don't promise zero — it's untrue and they'll remember.","State what you've done and how much it cuts the risk.","Honest risk reduction is more credible than a false guarantee."],"focus":["clarity","precision"],"placeholder":"I can't guarantee zero — nobody honestly can — but the specific failure that caused this can't recur, and we've tested the fix under load."},
    {"id":"pressure-ops-senior-09","level":"senior","profession":"operator","title":"The interruption mid-answer","scenario":"You're explaining the network redesign and a director cuts in: 'Just tell me the bottom line — does this save money or not?' You were three points from getting there. Answer the interruption directly, then offer to continue.","task":"Write a 2-sentence response that answers the interruption first, then offers the detail.","tips":["Give the bottom line they demanded, immediately.","Don't insist on finishing your planned path first.","Offer the supporting detail, but on their terms now."],"focus":["clarity","audience"],"placeholder":"Yes — $11M a year net of the transition cost; happy to walk through where it comes from if useful."},
    {"id":"pressure-ops-senior-10","level":"senior","profession":"operator","title":"'Whose fault was the miss?'","scenario":"A board member asks who's responsible for the delivery miss. Naming a scapegoat is tempting and cheap. The right answer owns it as the accountable executive while being honest about the system.","task":"Write a 2-sentence answer that owns accountability without scapegoating.","tips":["As the accountable exec, the answer starts with you.","Point at the system failure, not an individual.","Scapegoating in the boardroom always costs you later."],"focus":["impact","clarity"],"placeholder":"It's my accountability — the miss came from a demand signal we should have caught, and I own fixing that."},
    {"id":"pressure-ops-senior-11","level":"senior","profession":"operator","title":"The hostile analyst-style question","scenario":"In a mock earnings prep, the CFO role-plays a hostile analyst: 'Your inventory is bloated and it looks like you've lost control of operations.' You need to answer the substance without matching the tone.","task":"Write a 2-3 sentence answer that addresses the substance calmly and factually.","tips":["Don't react to the tone; answer the substance.","Reframe 'bloated' as the deliberate, temporary buffer it is.","Calm facts beat matching the hostility."],"focus":["clarity","precision"],"placeholder":"The inventory build is deliberate — we're carrying buffer stock through a supplier transition, and it unwinds by Q1."},
    {"id":"pressure-ops-senior-12","level":"senior","profession":"operator","title":"'Just give me a date' on the restart","scenario":"During the plant fire recovery, the CEO presses for a firm restart date you don't fully control (permits, inspections). She wants a date, not a range of caveats. Give your best committed date with the one real dependency.","task":"Write a 2-sentence answer with a committed date and the single genuine dependency.","tips":["Give a date, not a fog of caveats — she needs to plan.","Name the one dependency that could move it, not five.","Commit and flag; don't refuse to commit."],"focus":["clarity","precision"],"placeholder":"I'm committing to Thursday the 22nd; the one thing that could push it is the fire-marshal sign-off, which I expect Tuesday."},
    {"id":"pressure-ops-senior-13","level":"senior","profession":"operator","title":"The question you can't answer publicly","scenario":"In an all-hands, an employee asks whether the Memphis closure means their site is next. You can't confirm or deny future decisions, but a non-answer breeds fear. Answer honestly within what you can say.","task":"Write a 2-3 sentence answer that's honest about what you can and can't say, without stonewalling.","tips":["Be honest about the limit rather than pretending it away.","Say what you can commit to — process, notice, honesty.","A respectful 'here's what I can tell you' beats a corporate dodge."],"focus":["clarity","audience"]},
    {"id":"pressure-ops-senior-14","level":"senior","profession":"operator","title":"'Why should we trust your number?'","scenario":"A director openly doubts your capacity forecast after a past miss. Getting wounded won't help. Answer the trust question by pointing to what's changed in how the number was built.","task":"Write a 2-3 sentence answer that rebuilds trust with the method, not with reassurance.","tips":["Don't ask for trust — earn it with the improved method.","Name what's different in how this forecast was built.","Method beats promises when credibility is the issue."],"focus":["precision","impact"]},
    {"id":"pressure-ops-senior-15","level":"senior","profession":"operator","title":"The two-part question, both parts","scenario":"A director asks: 'What caused the safety incident, and are other sites exposed?' Under pressure you answer the first and forget the second. Answer both parts explicitly.","task":"Write a 3-sentence answer that addresses both the cause and the cross-site exposure.","tips":["Two-part questions need two-part answers — track both.","Answer the cause, then explicitly address exposure elsewhere.","Missing the second part reads as evasion or inattention."],"focus":["clarity","structure"],"placeholder":"The cause was a guarding gap on one machine type; we've checked the other sites, and two have the same equipment, which we're inspecting today."},
    {"id":"pressure-ops-senior-16","level":"senior","profession":"operator","title":"'You said that last quarter'","scenario":"You commit to fixing on-time delivery and a director notes you said the same thing last quarter. It stings because it's fair. Answer by owning the repeat and stating what's concretely different now.","task":"Write a 2-3 sentence answer that owns the repeated promise and shows what's actually different.","tips":["Concede the fair point — denying it destroys credibility.","Name the specific, verifiable difference this time.","'Here's what changed' beats 'trust me this time.'"],"focus":["impact","precision"]},
    {"id":"pressure-ops-senior-17","level":"senior","profession":"operator","title":"The CEO's rapid-fire in the hallway","scenario":"The CEO catches you in the hallway: 'Peak ready? Automation on track? Memphis on schedule?' Three questions, ten seconds. Answer each crisply without merging them into mush.","task":"Write three short answers, one per question, in order.","tips":["Answer each in one clause; don't blur them together.","Keep the order she asked — it helps her track.","Crisp trios show command; rambling shows overwhelm."],"focus":["concision","clarity"],"placeholder":"Peak: ready but one hiring gap in the Southeast. Automation: on plan, four of five phases live. Memphis: on schedule, wind-down starts the 1st."},
    {"id":"pressure-ops-senior-18","level":"senior","profession":"operator","title":"Defending the buffer under fire","scenario":"The CFO attacks your safety-stock buffer in front of the exec team as tying up cash needlessly. You believe cutting it risks revenue. Defend it with the exposure math, not with operational anxiety.","task":"Write a 2-3 sentence defense grounded in revenue exposure, delivered without defensiveness.","tips":["Answer in his currency — revenue at risk, not service levels.","Offer the conditional: cut it after the transition, not before.","Steady math beats an anxious plea to keep the stock."],"focus":["impact","precision"],"placeholder":"If we halve it now, we put roughly $40M of contracted revenue at stockout risk during the transition — I'd cut it the moment the transition clears, not before."},
    {"id":"pressure-ops-senior-19","level":"senior","profession":"operator","title":"'What are you NOT telling us?'","scenario":"A skeptical director asks what you're not telling the board about the automation program. It's a trust probe. Answer by proactively surfacing the real risk you'd been about to cover — transparency defuses it.","task":"Write a 2-3 sentence answer that surfaces the genuine risk rather than deflecting the probe.","tips":["The right answer volunteers the concern, not a denial.","Name the real risk you'd been going to raise anyway.","Volunteered candor rebuilds the trust the question doubts."],"focus":["clarity","impact"]},
    {"id":"pressure-ops-senior-20","level":"senior","profession":"operator","title":"The customer-CEO's angry call","scenario":"The CEO of your largest customer calls, angry about repeated late shipments, and demands to know if you even have a plan. You have one. Answer the demand directly with the commitment before any explanation.","task":"Write a 2-3 sentence response that leads with the commitment, then briefly the cause.","tips":["Answer 'do you have a plan' with the plan, dated, first.","Explanation after commitment reads as accountable, not excuse.","Match their intensity with specifics, not apology."],"focus":["impact","audience"],"placeholder":"Yes — you'll see on-time back above 98% within three weeks, and I'll send you numbers every Friday; the cause was a carrier failure we've now replaced."},
    {"id":"pressure-ops-senior-21","level":"senior","profession":"operator","title":"The 'simple yes or no' that isn't","scenario":"A director demands a yes or no on whether the footprint plan will hit its savings target. The honest answer has a condition. Lead with the direct answer, then the one condition — don't hide behind 'it's complicated.'","task":"Write a 2-sentence answer that gives a clear lead answer plus the single real condition.","tips":["Give the closest thing to yes or no you honestly can.","Then the one condition — not a paragraph of hedging.","'Yes, provided X' is a direct answer; 'it's complicated' is not."],"focus":["clarity","precision"],"placeholder":"Yes, provided the transition stays on schedule — and I've built a two-month contingency into that plan."},
    {"id":"pressure-ops-senior-22","level":"senior","profession":"operator","title":"The pressure to over-commit","scenario":"Sales and the CEO are pushing you to promise the full $45M pipeline can be supplied. You know it's $30M realistically. The pressure is real, but a promise you can't keep is worse. Hold the honest number under pressure.","task":"Write a 2-3 sentence response that holds the realistic number without caving to the room.","tips":["Don't buy peace with a number you can't deliver.","State what you can commit to and the path to more.","Holding an honest line under pressure is the whole skill."],"focus":["impact","clarity"],"placeholder":"I can commit to $30M this year and I won't promise beyond what we can build — but here's the investment that would unlock the rest by next year."},
    {"id":"pressure-ops-senior-23","level":"senior","profession":"operator","title":"The technical trap question","scenario":"A director with an operations background asks a detailed question about your OEE calculation methodology, testing whether you actually know your numbers. Answer the technical substance directly, then return to the point.","task":"Write a 2-3 sentence answer that handles the technical detail credibly, then reconnects to the business point.","tips":["Answer the technical question squarely — dodging fails the test.","Then bridge back to what it means for the business.","Competence on detail earns the right to the big picture."],"focus":["precision","clarity"]},
    {"id":"pressure-ops-senior-24","level":"senior","profession":"operator","title":"'Convince me not to close this plant'","scenario":"The CEO challenges you to defend keeping a plant you've recommended closing, to test your conviction. You must engage the challenge honestly, not cave, while showing you've genuinely weighed the other side.","task":"Write a 2-3 sentence answer that engages the challenge and holds your recommendation.","tips":["Show you've genuinely considered the case to keep it.","Then restate why closure still wins, on the evidence.","Engaging the counter-case strengthens your position, not weakens it."],"focus":["impact","structure"]},
    {"id":"pressure-ops-senior-25","level":"senior","profession":"operator","title":"The 'I need it now' with no data","scenario":"Mid-crisis, the board chair demands the financial exposure number immediately. You have partial data and any number you give will be quoted back. Give a responsible bounded answer, not a false precision or a stall.","task":"Write a 2-sentence answer that gives a defensible bounded estimate and commits to firming it.","tips":["A responsible range beats both a made-up point and a stall.","Bound it and say what would tighten it.","Commit to the firm number with a time."],"focus":["precision","clarity"],"placeholder":"My best estimate is $8-12M, driven mostly by lost orders and cleanup; I'll narrow that to a firm number by end of day once the claims data is in."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-ops-senior-01","level":"senior","profession":"operator","title":"Before and after for automation","scenario":"You're pitching the $42M automation program to the board. Numbers alone won't move them; you need a vivid before-and-after. Paint the operation as it is today versus as it will be, so the investment feels inevitable.","task":"Write a 3-4 sentence before/after that frames the change the investment buys.","tips":["Make 'today' concrete and slightly painful — the reader should feel it.","Make 'after' specific and measurable, not utopian.","The gap between them is your case; let them feel it, not just read it."],"focus":["impact","structure"]},
    {"id":"narrative-ops-senior-02","level":"senior","profession":"operator","title":"Concrete stakes for the footprint decision","scenario":"Your footprint memo says the network is 'suboptimal' and closing sites will 'improve efficiency.' Abstract words move no one. Make the stakes concrete: what it costs to do nothing, in terms the board feels.","task":"Rewrite the stakes as a concrete cost of inaction in dollars and customer terms.","tips":["'Suboptimal' costs nothing; a real number costs something.","Frame the cost of the status quo, not just the benefit of change.","Concrete stakes create urgency that abstractions can't."],"focus":["impact","precision"],"placeholder":"Running seven DCs instead of four costs us $11M a year and leaves 20% of customers a day slower than the competition."},
    {"id":"narrative-ops-senior-03","level":"senior","profession":"operator","title":"Pre-empt the CFO's objection","scenario":"You know the CFO's strongest objection to the automation case is the restructuring charge it triggers this year. Rather than let him raise it, pre-empt it in your pitch. Name it and answer it before he does.","task":"Write 2-3 sentences that raise the CFO's strongest objection and answer it.","tips":["Name the objection before your opponent does — it disarms it.","Answer it honestly, not dismissively.","Pre-empting shows you've done the thinking they were about to."],"focus":["impact","structure"],"placeholder":"I know the concern is the $8M restructuring charge this year — it's real, but it's one-time, and the annual savings clear it in under seven months."},
    {"id":"narrative-ops-senior-04","level":"senior","profession":"operator","title":"The change story for the workforce","scenario":"You're announcing a major operations reorganization to 4,000 employees. A list of new reporting lines feels arbitrary and cold. You need a narrative: why we're changing, what it means for them, where we're going.","task":"Write a 3-4 sentence change narrative for the workforce.","tips":["Start with the 'why' they can believe, not the org chart.","Make the destination concrete and worth reaching.","Acknowledge the disruption honestly; a story that ignores it fails."],"focus":["impact","audience"]},
    {"id":"narrative-ops-senior-05","level":"senior","profession":"operator","title":"Selling resilience investment","scenario":"You want the board to fund $15M in supply-chain resilience — dual sourcing, buffer capacity. Resilience is a hard sell because it prevents problems that haven't happened. Make the invisible risk vivid and the investment feel prudent.","task":"Write a 3-4 sentence persuasion that makes the unfelt risk concrete.","tips":["Prevention is a hard sell — make the avoided disaster vivid.","Anchor on a near-miss or a peer's failure they'll recognize.","Frame it as insurance with a return, not just a cost."],"focus":["impact","structure"]},
    {"id":"narrative-ops-senior-06","level":"senior","profession":"operator","title":"The turnaround story arc","scenario":"You're presenting a plant turnaround to the exec committee. A list of tactics is forgettable. An arc — where the plant was, the turning point, where it's headed — makes the case memorable and fundable.","task":"Write a 3-4 sentence turnaround narrative with a clear arc.","tips":["Establish the low point honestly so the recovery means something.","Name the turning point — the decision or change that shifted it.","End with the trajectory, not just the current state."],"focus":["impact","structure"]},
    {"id":"narrative-ops-senior-07","level":"senior","profession":"operator","title":"Pre-empt the 'why not competitors' objection","scenario":"You're recommending a specific logistics partner. The exec team's strongest counter is 'why not the incumbent we already know?' Raise and answer that objection inside your pitch, before it's thrown at you.","task":"Write 2-3 sentences that surface and defeat the incumbent objection.","tips":["Name the obvious counter-choice yourself.","Give the specific reason the alternative wins anyway.","Answered objections become reasons to say yes."],"focus":["impact","precision"]},
    {"id":"narrative-ops-senior-08","level":"senior","profession":"operator","title":"Making the KPI trend a story","scenario":"Your KPI review shows six months of improving cost-per-unit, but presented as a flat chart it's inert. Turn the trend into a narrative: what we changed, what it produced, what it means for next year.","task":"Write a 3-sentence narrative that turns the cost trend into a story with cause and consequence.","tips":["A trend is data; a narrative adds cause and stakes.","Connect the improvement to a decision you made — give it an author.","End with the forward implication, not just the past."],"focus":["structure","impact"],"placeholder":"Six months ago we re-sequenced the line; since then cost per unit has fallen 6% — and if we automate the pick station, we hold that gain even as volume grows."},
    {"id":"narrative-ops-senior-09","level":"senior","profession":"operator","title":"The recall, framed as protection","scenario":"You're persuading a nervous CEO to approve the voluntary recall. Framed as an admission of failure, it's terrifying; framed as protecting customers and the brand, it's leadership. Choose the frame that makes the right call easier.","task":"Write a 2-3 sentence framing that positions the recall as brand protection, not admission of failure.","tips":["The same fact reads differently depending on the frame.","Frame the recall as decisive protection, not confession.","Give the CEO a story she can repeat to the board."],"focus":["impact","audience"],"placeholder":"Recalling this lot now — before a single customer is harmed — is us protecting the brand, and it's a far smaller story than a field failure would be."},
    {"id":"narrative-ops-senior-10","level":"senior","profession":"operator","title":"Persuading plant managers to adopt","scenario":"You need ten skeptical plant managers to adopt the predictive-maintenance system. They've seen initiatives fail. Persuade them with a before/after grounded in their reality — the 3am calls, the blown weekends — not a corporate benefit.","task":"Write a 3-4 sentence persuasion built on their lived before/after.","tips":["Speak to their pain, not the corporate benefit.","Before: the firefighting they know. After: what changes on their shift.","One respected peer's result beats any executive claim."],"focus":["impact","audience"]},
    {"id":"narrative-ops-senior-11","level":"senior","profession":"operator","title":"The capacity crisis, made urgent","scenario":"Sales demand is outrunning your capacity, and you need the board to fund a new line now, not next year. Waiting has a cost you must make vivid: the deals you'll turn away, the customers you'll lose. Create urgency without alarmism.","task":"Write a 3-sentence narrative that makes the cost of waiting concrete and urgent.","tips":["Quantify what a year's delay costs — deals, share, customers.","Urgency comes from concrete loss, not exclamation.","End with the window: why now, not later."],"focus":["impact","precision"],"placeholder":"Every quarter we wait, we turn away roughly $8M of contracted demand and hand it to a competitor who then owns that customer — a year's delay isn't neutral, it's a permanent share loss."},
    {"id":"narrative-ops-senior-12","level":"senior","profession":"operator","title":"Pre-empt the union's strongest objection","scenario":"You're introducing a productivity program to union leadership. Their strongest objection is that 'efficiency' means job cuts. If you don't address it head-on, nothing else you say lands. Raise it and answer it first.","task":"Write 2-3 sentences that name the job-security fear and address it honestly, up front.","tips":["Their real objection is jobs — say it before they do.","Be honest: if there's attrition-only, say so; if not, don't pretend.","Addressing the fear first earns a hearing for the rest."],"focus":["impact","audience"]},
    {"id":"narrative-ops-senior-13","level":"senior","profession":"operator","title":"The vision for the operation","scenario":"As new COO you're setting a three-year vision for operations at the leadership offsite. A list of targets is uninspiring. Paint a picture of the operation you're building — what it will be capable of that it isn't today.","task":"Write a 3-4 sentence vision that contrasts today's operation with the future you're building.","tips":["A vision is a destination people can picture, not a target list.","Contrast makes it vivid: from reactive to predictive, from X to Y.","Make it ambitious but grounded in specific capabilities."],"focus":["impact","structure"]},
    {"id":"narrative-ops-senior-14","level":"senior","profession":"operator","title":"Persuading the CFO on working capital","scenario":"You want the CFO to accept a temporary inventory build to protect service through a supplier transition. His instinct is that inventory is waste. Reframe the build as a deliberate, time-boxed investment in revenue protection.","task":"Write a 2-3 sentence reframe that persuades the CFO the build is prudent, not wasteful.","tips":["Reframe 'excess inventory' as 'revenue insurance, time-boxed.'","Give the unwind date so it doesn't feel permanent.","Speak to what it protects, in his currency."],"focus":["impact","precision"],"placeholder":"This isn't excess stock, it's a time-boxed hedge — we hold it only through the supplier transition, and it protects $40M of contracted revenue from a stockout."},
    {"id":"narrative-ops-senior-15","level":"senior","profession":"operator","title":"The safety case, made human","scenario":"You're asking the board to fund a $9M safety-and-reliability program. TRIR statistics leave directors cold. Make the stakes human — an injury prevented is a person who goes home — without being manipulative.","task":"Write a 2-3 sentence framing that makes the safety investment concrete and human.","tips":["Statistics are forgettable; a person going home is not.","Keep it honest and grounded, not sentimental.","Pair the human stake with the business case, don't replace it."],"focus":["impact","audience"]},
    {"id":"narrative-ops-senior-16","level":"senior","profession":"operator","title":"Pre-empt 'the market will recover'","scenario":"You're recommending capacity cuts because demand has structurally declined. The optimists on the exec team will argue the market will bounce back. Pre-empt that objection with evidence it's structural, not cyclical.","task":"Write 2-3 sentences that raise the 'it'll recover' hope and answer it with evidence.","tips":["Name the optimistic counter directly.","Distinguish structural from cyclical with specific evidence.","Answered hope is more persuasive than ignored hope."],"focus":["impact","precision"]},
    {"id":"narrative-ops-senior-17","level":"senior","profession":"operator","title":"The 'why us, why now' for the partner","scenario":"You're pitching a strategic operations partnership to a major vendor's leadership. They have other customers. You need a narrative for why this partnership, at this moment, benefits them — not just a list of your requirements.","task":"Write a 3-sentence narrative framing the mutual case for the partnership.","tips":["Lead with what's in it for them, not your requirements.","Frame the timing: why now is the moment for both sides.","A partnership narrative is about the shared future, not your ask."],"focus":["impact","audience"]},
    {"id":"narrative-ops-senior-18","level":"senior","profession":"operator","title":"The recovery story after the outage","scenario":"A week after the ERP outage, you're addressing the operations org. You could dwell on the failure or frame it as a story of response and learning. Choose the narrative that acknowledges the pain but leaves the org stronger.","task":"Write a 3-4 sentence narrative that honestly frames the outage as a story with a forward turn.","tips":["Acknowledge the failure honestly — spin backfires here.","Frame the response as the team at its best.","End on what's permanently better because of it."],"focus":["impact","audience"]},
    {"id":"narrative-ops-senior-19","level":"senior","profession":"operator","title":"Making the abstract risk concrete","scenario":"You're warning the board about single-points-of-failure in the network. 'Concentration risk' is abstract and easy to defer. Make one specific failure scenario concrete enough that the board can't unsee it.","task":"Write a 2-3 sentence concrete scenario that makes the concentration risk unignorable.","tips":["Turn 'concentration risk' into a specific, plausible bad day.","Walk the board through what actually happens if it fails.","A vivid scenario funds mitigation that a risk category can't."],"focus":["impact","precision"],"placeholder":"If the Columbus plant goes down for a month — a fire, a flood — we lose 60% of gross margin and can't recover for a quarter; that's the exposure one site carries today."},
    {"id":"narrative-ops-senior-20","level":"senior","profession":"operator","title":"Pre-empt 'we can't afford it now'","scenario":"You're asking for automation capex in a tight budget year. The strongest objection is timing — 'not this year.' Pre-empt it by framing the cost of delay as larger than the cost of acting.","task":"Write 2-3 sentences that raise the timing objection and reframe delay as the more expensive choice.","tips":["Name the 'not now' objection before it's raised.","Show that waiting costs more than acting — quantified.","Reframe the decision from 'spend or save' to 'when to spend.'"],"focus":["impact","precision"]},
    {"id":"narrative-ops-senior-21","level":"senior","profession":"operator","title":"The customer-win-back narrative","scenario":"You're proposing a plan to win back the customer you lost to a competitor. The exec team is cynical. You need a narrative that credibly explains what went wrong, what's now different, and why the customer would return.","task":"Write a 3-4 sentence narrative for the win-back case.","tips":["Own honestly why they left — cynicism sees through spin.","Show the specific, verifiable change since.","Frame the return as a lower-risk bet for them, with proof."],"focus":["impact","structure"]},
    {"id":"narrative-ops-senior-22","level":"senior","profession":"operator","title":"Persuading peers to share the cost","scenario":"The automation program benefits operations but the cost hits a shared budget with sales and finance. You need your executive peers to back it, which means framing the benefit as theirs, not just yours.","task":"Write a 2-3 sentence pitch that frames the automation benefit for your peers' goals.","tips":["Persuasion across peers means their wins, not yours.","Frame it as capacity for sales, margin for finance.","Shared benefit unlocks shared funding."],"focus":["impact","audience"]},
    {"id":"narrative-ops-senior-23","level":"senior","profession":"operator","title":"The 'status quo is the risk' reframe","scenario":"Your network redesign is risky, and the board is risk-averse. But doing nothing is also risky — slower service, higher cost, growing competitive gap. Reframe so the status quo, not the change, is the dangerous option.","task":"Write a 2-3 sentence reframe that positions inaction as the greater risk.","tips":["Boards fear change; make them fear standing still more.","Quantify the drift of the status quo over time.","The reframe: not 'change is risky' but 'not changing is riskier.'"],"focus":["impact","structure"],"placeholder":"The real risk isn't the redesign — it's staying with a seven-DC network that costs $11M more a year and loses ground to a competitor every quarter we wait."},
    {"id":"narrative-ops-senior-24","level":"senior","profession":"operator","title":"The offsite call to action","scenario":"You're closing the operations leadership offsite. You've laid out the strategy; now you need people to leave committed, not just informed. Craft a close that converts the plan into a shared mission with a first step.","task":"Write a 3-sentence closing call to action for the leadership team.","tips":["End on commitment, not summary.","Give one concrete first step everyone owns.","Make the mission feel shared and worth the effort."],"focus":["impact","audience"]},
    {"id":"narrative-ops-senior-25","level":"senior","profession":"operator","title":"The one-slide persuasion","scenario":"You have a single slide and ninety seconds to persuade the board to approve the footprint plan. No room for a full narrative — you need the before/after, the stake, and the ask compressed into a persuasive whole.","task":"Write the 3-4 sentence script for that single persuasive slide.","tips":["Compress the arc: today's cost, the change, the payoff, the ask.","Every sentence must earn its place at this length.","End on the ask so the last words are the decision."],"focus":["impact","concision"],"placeholder":"Today seven DCs cost us $11M a year and leave a fifth of customers slow; four regional hubs fix both, for a one-time $9M and an 18-month payback — I'm asking you to approve it today."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-ops-senior-01","level":"senior","profession":"operator","title":"Announcing the plant closure","scenario":"You must tell the Memphis site that it's closing and 340 jobs will end over twelve months. The instinct is to bury the news under context and reassurance. Clear is kind: the closure fact has to come first, plainly.","task":"Write the opening 2-3 sentences of the closure announcement, front-loading the news.","tips":["Say the closure in the first sentence — delaying it is cruel, not kind.","No corporate cushioning before the fact; it reads as evasion.","Follow immediately with what it means for them: timeline, support."],"focus":["clarity","impact"],"placeholder":"I have hard news: we've decided to close the Memphis site, and operations here will wind down over the next twelve months."},
    {"id":"hard-ops-senior-02","level":"senior","profession":"operator","title":"The clean 'no' to a plant manager","scenario":"A respected plant manager has asked repeatedly for capex you can't approve this cycle. Your past answers have been soft enough that he keeps asking. He deserves a clean no with a real reason.","task":"Write a 2-3 sentence response that says no clearly and gives the honest reason.","tips":["A soft no that reads as maybe wastes his effort and yours.","Say no, then the real reason, in plain terms.","Clarity respects him more than false hope does."],"focus":["clarity","impact"],"placeholder":"The answer is no for this cycle — the capital's committed to the automation program, and I can't reopen that."},
    {"id":"hard-ops-senior-03","level":"senior","profession":"operator","title":"Behavior, impact, ask on a peer","scenario":"A peer executive keeps committing operations to customer dates without checking with you, causing missed promises. You need to give direct feedback using behavior, impact, ask — not vent or hint.","task":"Write a 3-sentence feedback message: the specific behavior, its impact, and your ask.","tips":["Name the behavior factually, without judgment words.","State the concrete impact — missed dates, damaged trust.","End with a specific, doable ask, not a complaint."],"focus":["clarity","structure"],"placeholder":"When you commit dates to customers without checking capacity with me, we miss roughly one in three of them — I'm asking that we clear any customer date through ops before it's promised."},
    {"id":"hard-ops-senior-04","level":"senior","profession":"operator","title":"Telling the CEO the target will miss","scenario":"You now know the annual cost target will miss by $4M and the CEO expects to hit it. The temptation is to soften with optimism about recovery. Clear is kind: she needs the miss stated plainly to plan.","task":"Write a 2-3 sentence message that states the miss clearly before any recovery framing.","tips":["Lead with the miss and the number — she can't plan around optimism.","Don't wrap the bad news in a hopeful maybe.","State what you're doing after the fact is clear, not instead of it."],"focus":["clarity","impact"],"placeholder":"We're going to miss the cost target by about $4M this year — the resin price spike we couldn't offset — and here's what I'm doing to contain it."},
    {"id":"hard-ops-senior-05","level":"senior","profession":"operator","title":"The layoff conversation opener","scenario":"You're leading a workforce reduction of 200 roles across two plants. You'll address the affected employees directly. The message must be honest and respectful, front-loading the hard fact without cruelty or corporate fog.","task":"Write the opening 2-3 sentences for the workforce reduction announcement.","tips":["Say what's happening clearly and early — respect through honesty.","Avoid euphemisms like 'rightsizing'; people see through them.","Immediately follow with the support and process that matters to them."],"focus":["clarity","audience"]},
    {"id":"hard-ops-senior-06","level":"senior","profession":"operator","title":"Declining the CEO's timeline","scenario":"The CEO wants the automation cutover accelerated by two months. You believe it's unsafe and must say no to your boss. A clean, respectful no with the reason beats a reluctant yes you'll regret.","task":"Write a 2-3 sentence response declining the accelerated timeline with your reason.","tips":["Say no to the timeline clearly, not with vague concerns.","Give the specific risk that drives your no.","Offer what you can do, so the no isn't a dead end."],"focus":["clarity","impact"],"placeholder":"I can't do the accelerated timeline safely — compressing it two months means cutting the parallel-run period that protects service, and I won't risk that; here's the fastest safe path."},
    {"id":"hard-ops-senior-07","level":"senior","profession":"operator","title":"The supplier termination call","scenario":"After three failed corrective plans, you're terminating a long-standing supplier whose leadership you've known for years. The message must be clear and final, delivered with respect but without leaving false hope of reprieve.","task":"Write the 2-3 sentence core of the termination message.","tips":["State the decision as final — hedging invites more failed promises.","Be respectful about the relationship without softening the decision.","Give the honest reason: the corrective plans didn't hold."],"focus":["clarity","impact"]},
    {"id":"hard-ops-senior-08","level":"senior","profession":"operator","title":"Telling sales they can't have it","scenario":"Sales has built a $45M pipeline on a product line you can only supply $30M of. You have to tell them, and they'll be angry. Clear is kind: give them the real number now, not a hopeful one that fails later.","task":"Write a 2-3 sentence message that delivers the constraint clearly and helps them act.","tips":["Give the real number — a soft one just delays the anger.","Frame it as what to plan around, not just bad news.","Offer the path to more capacity so it's not purely a no."],"focus":["clarity","impact"],"placeholder":"I can support $30M of the pipeline this year, not $45M — I know that's hard, so let's prioritize the must-win deals, and here's the investment that unlocks the rest next year."},
    {"id":"hard-ops-senior-09","level":"senior","profession":"operator","title":"Owning the recall to customers","scenario":"You're signing the customer recall letter. It's a hard message — your product could fail. The instinct is to minimize with qualifiers. Clear is kind: customers need to understand the risk and the action plainly.","task":"Write the 2-3 sentence core of the customer recall message, stated honestly.","tips":["Don't minimize a safety risk with 'may under certain conditions.'","State plainly what could go wrong and what to do.","Honesty here protects customers and, ultimately, the brand."],"focus":["clarity","audience"]},
    {"id":"hard-ops-senior-10","level":"senior","profession":"operator","title":"Feedback to an underperforming director","scenario":"A plant director reporting to you has let safety metrics slip for two quarters while blaming external factors. You need to deliver hard performance feedback using behavior, impact, ask — directly, not through hints.","task":"Write a 3-sentence feedback message: behavior, impact, ask.","tips":["Name the pattern factually, not as character judgment.","State the impact: the safety trend and what it risks.","Make the ask specific and time-bound."],"focus":["clarity","structure"]},
    {"id":"hard-ops-senior-11","level":"senior","profession":"operator","title":"The 'we're behind' to the board","scenario":"The automation program is a quarter behind schedule and you told the board it was on track last time. You must correct that clearly. Front-load the slip; don't bury it in a paragraph of progress.","task":"Write a 2-3 sentence board update that states the delay clearly and early.","tips":["Lead with the slip and its size — the board hates buried surprises.","Own that you reported on-track before; don't pretend continuity.","State the recovery plan after the fact, not in place of it."],"focus":["clarity","impact"],"placeholder":"I need to correct my last update: the automation program is a quarter behind, driven by the conveyor redesign, and here's how we recover the schedule."},
    {"id":"hard-ops-senior-12","level":"senior","profession":"operator","title":"Denying the exception request","scenario":"During a hiring freeze, a valued plant manager asks you to make an exception for a role you can't justify over others' equally strong requests. You have to deny it cleanly and explain why fairness requires the no.","task":"Write a 2-3 sentence response that denies the exception clearly and explains the fairness reason.","tips":["Say no clearly; a maybe invites lobbying.","Give the fairness reason — others have equal claims.","Respect the request even as you decline it."],"focus":["clarity","impact"]},
    {"id":"hard-ops-senior-13","level":"senior","profession":"operator","title":"Telling the customer their order is late","scenario":"A key customer's large order will ship two weeks late due to your production issue. You must tell them before they discover it. Front-load the bad news, own it, then the recovery — not the other way around.","task":"Write a 2-3 sentence message that leads with the delay and owns it.","tips":["Tell them before they find out — that's the kind thing.","Lead with the delay and the new date, plainly.","Own the cause; don't hide behind vague 'supply issues.'"],"focus":["clarity","audience"],"placeholder":"I need to tell you directly: your order will ship two weeks late, on the 28th, because of a line failure at our end — here's what we're doing to prevent a repeat."},
    {"id":"hard-ops-senior-14","level":"senior","profession":"operator","title":"The reorganization that demotes a peer","scenario":"Your operations reorganization effectively reduces a long-serving director's scope. You must tell him directly before it's public. The message must be honest about the change without dressing a demotion as an opportunity.","task":"Write a 2-3 sentence message that states the scope change honestly and respectfully.","tips":["Don't disguise a reduction as a 'new opportunity' — he'll know.","State the change clearly, then the reasoning.","Respect his tenure by being straight, not by spinning."],"focus":["clarity","impact"]},
    {"id":"hard-ops-senior-15","level":"senior","profession":"operator","title":"Admitting the outage was preventable","scenario":"The board asks whether the outage was preventable. It was — a known gap in the failover runbook. The easy answer blames complexity; the honest one admits the gap. Clear is kind, and honesty here rebuilds trust.","task":"Write a 2-3 sentence answer that admits preventability plainly and owns it.","tips":["Admit it was preventable if it was — hedging destroys trust.","Name the specific gap without drowning it in technicality.","Own it and state the fix; ownership is what rebuilds trust."],"focus":["clarity","impact"],"placeholder":"Yes, it was preventable — our failover runbook had a gap we should have caught, and I own that; we've now closed it and tested the fix."},
    {"id":"hard-ops-senior-16","level":"senior","profession":"operator","title":"The 'no bonus this year' message","scenario":"Operations missed the targets that fund the site bonus, and you must tell the plant that there's no bonus this year. The message must be honest about why, respectful of their effort, and free of false comfort.","task":"Write a 2-3 sentence message delivering the no-bonus news clearly and respectfully.","tips":["State it plainly; a vague message breeds worse rumors.","Explain the honest reason without blaming the workforce.","Acknowledge the effort without pretending the outcome was different."],"focus":["clarity","audience"]},
    {"id":"hard-ops-senior-17","level":"senior","profession":"operator","title":"Correcting the CEO in the meeting","scenario":"In the exec meeting the CEO states an operations fact that's wrong and is about to repeat it to the board. You must correct her, in the room, respectfully but clearly, before the error spreads.","task":"Write a 1-2 sentence correction that's clear and respectful in front of peers.","tips":["Correct the fact, not the person — keep it about the number.","Do it plainly; a mumbled hedge lets the error stand.","Offer the right figure immediately so it's constructive."],"focus":["clarity","impact"],"placeholder":"One correction before this goes to the board — on-time is 94%, not 97%; I want the number right for them."},
    {"id":"hard-ops-senior-18","level":"senior","profession":"operator","title":"Telling a top performer they're not promoted","scenario":"A strong operations manager expected the VP role and didn't get it. You must tell them directly. The message needs to be honest about the gap without either crushing them or offering false timelines.","task":"Write a 2-3 sentence message delivering the news with honesty and a real path.","tips":["Say they didn't get it clearly — don't lead with consolation.","Name the specific development gap, factually.","Offer a real, honest path — not a hollow 'next time.'"],"focus":["clarity","structure"]},
    {"id":"hard-ops-senior-19","level":"senior","profession":"operator","title":"The workforce message on automation cuts","scenario":"Automation will eliminate 60 roles at a plant, with attrition and redeployment covering some but not all. You must tell the workforce honestly — not hide the cuts behind 'productivity gains.' Clear is kind here.","task":"Write a 2-3 sentence message that states the role reductions honestly, with the mitigation.","tips":["Don't hide job losses inside 'productivity' language.","State how many roles end and how many are redeployed.","Honesty now beats the trust damage of discovered spin."],"focus":["clarity","audience"],"placeholder":"Automation will change 60 roles at this plant — we'll cover about 40 through retraining and attrition, but around 20 positions will end, and I won't pretend otherwise."},
    {"id":"hard-ops-senior-20","level":"senior","profession":"operator","title":"Declining the board member's pet idea","scenario":"A board member is pushing an operations idea — reshoring a component line — that you've analyzed and found uneconomic. You must decline it clearly with evidence, respecting their standing without agreeing to a bad plan.","task":"Write a 2-3 sentence response that declines the idea with evidence, respectfully.","tips":["Respect the source; disagree with the idea on evidence.","State the specific reason it doesn't work — the number.","A clear, evidenced no is more respectful than polite avoidance."],"focus":["clarity","precision"]},
    {"id":"hard-ops-senior-21","level":"senior","profession":"operator","title":"The safety stand-down message","scenario":"After a serious near-miss, you're ordering a full safety stand-down that halts production for a day, costing real output. You must tell the org why this hard, expensive call is non-negotiable. Clear and firm.","task":"Write a 2-3 sentence message that delivers the stand-down decision firmly and explains why.","tips":["State the stand-down as a decision, not a proposal.","Make clear it's non-negotiable — safety outranks output.","Explain the near-miss honestly so people understand the why."],"focus":["clarity","impact"],"placeholder":"We're standing down all production tomorrow — no exceptions — because yesterday's near-miss came too close to a fatality, and nothing we ship is worth that risk."},
    {"id":"hard-ops-senior-22","level":"senior","profession":"operator","title":"Telling finance the savings won't come","scenario":"A cost-savings program the CFO booked into the plan won't deliver as promised — it'll come in $3M short. You must tell him before quarter close. Front-load the shortfall; don't cushion it with the parts that did work.","task":"Write a 2-3 sentence message stating the savings shortfall clearly and early.","tips":["Lead with the shortfall number — he's planning around it.","Don't open with the parts that worked to soften the miss.","State the cause and any partial recovery after the fact."],"focus":["clarity","impact"],"placeholder":"The efficiency program will come in about $3M short of the booked $10M — the labor savings landed but the scrap reduction didn't — and I wanted you to have that before close."},
    {"id":"hard-ops-senior-23","level":"senior","profession":"operator","title":"The 'this isn't working' to a partner","scenario":"A strategic logistics partnership isn't delivering and you need to tell their executive it's on notice. The message must be direct enough to signal real risk to the relationship, without prematurely ending it.","task":"Write a 2-3 sentence message that clearly signals the partnership is at risk and what must change.","tips":["Be direct that the relationship is genuinely at risk.","Name the specific failures, not vague dissatisfaction.","State what has to change and by when — give a real line."],"focus":["clarity","impact"]},
    {"id":"hard-ops-senior-24","level":"senior","profession":"operator","title":"Owning a decision that went wrong","scenario":"A sourcing decision you championed led to the quality escape now hurting a customer. In front of the exec team, you must own the bad call rather than distribute blame. Clear ownership is the hard, right message.","task":"Write a 2-3 sentence statement that owns the decision and its consequence.","tips":["Own the call you made — distributing blame reads as weakness.","State what you'd do differently, specifically.","Ownership of failure is what earns trust for the recovery."],"focus":["clarity","impact"],"placeholder":"I pushed for that supplier, and this escape is the result — that's on me; here's what I'm changing in how we qualify sources so it doesn't recur."},
    {"id":"hard-ops-senior-25","level":"senior","profession":"operator","title":"The all-hands after the layoffs","scenario":"The day after announcing 200 layoffs, you address the remaining operations org. They're anxious and grieving colleagues. You must be honest that it was hard and necessary, without false cheer or pretending nothing happened.","task":"Write a 3-4 sentence all-hands opening that's honest about the layoffs and steadies the org.","tips":["Acknowledge the loss directly — don't paper over it.","Be honest that it was necessary without being cold.","Give the remaining team a clear, steady sense of forward."],"focus":["clarity","audience"]}
  ],
  "putting-it-together": [
    {"id":"together-ops-senior-01","level":"senior","profession":"operator","title":"The full board strategy memo","scenario":"You have thirty minutes to write the one-page operations strategy memo for the board: a governing idea, three pillars, the ask. It must lead with the point, carry a clear structure, and end on a decision.","task":"Write the full one-page memo (roughly 6-8 sentences) integrating all the skills.","tips":["Lead with the governing message, then three pillars, then the ask.","Every sentence earns its place; cut the warm-up.","End on the specific decision you need from the board."],"focus":["structure","impact"]},
    {"id":"together-ops-senior-02","level":"senior","profession":"operator","title":"Same message, three channels","scenario":"The plant-closure decision must go out three ways: a board memo, an all-hands script, and a customer note. The facts are the same; the register, length, and emphasis must differ. Match each to its audience and channel.","task":"Write the one core sentence for each of the three channels, showing how it shifts.","tips":["Board: decision and financials. Employees: what it means for them. Customers: continuity.","Register shifts with audience — same fact, different frame.","Channel shapes length: a memo, a script, a note each breathe differently."],"focus":["audience","clarity"]},
    {"id":"together-ops-senior-03","level":"senior","profession":"operator","title":"The crisis update, done right","scenario":"Ninety minutes into a major outage, you write the executive update. It needs BLUF, a fixed structure, precise numbers, no panic, and a clear next step — everything at once, under real time pressure.","task":"Write the full outage update (5-6 sentences) integrating lead, structure, precision, and presence.","tips":["Lead with impact and ETA; structure with fixed headers.","Precise numbers, no vague reassurance.","Steady tone, clear next update time — presence under pressure."],"focus":["structure","impact"],"placeholder":"Status: OMS down 90 minutes, cause identified. Impact: orders queuing, roughly 4,000, none lost."},
    {"id":"together-ops-senior-04","level":"senior","profession":"operator","title":"Edit the CFO's automation memo","scenario":"Your team drafted the automation investment memo for the CFO and it's bloated, buried, and jargon-heavy. You have one editing pass before it goes. Edit like a reader: fix the lead, cut the fat, translate the jargon.","task":"Rewrite the opening paragraph as your edited version (3-4 sentences).","tips":["Move the ask and payback to sentence one.","Cut hedges and nominalizations ruthlessly.","Translate ops jargon into the CFO's frame."],"focus":["concision","audience"],"placeholder":"We're asking to approve $42M for warehouse automation, with a 3.1-year payback."},
    {"id":"together-ops-senior-05","level":"senior","profession":"operator","title":"The pipeline-review constraint message","scenario":"At the revenue pipeline review you must deliver a capacity constraint to sales leadership: audience-first framing, a clear structure, a hard message, and answers to the pushback you'll get. All in one integrated message.","task":"Write the full message (5-6 sentences) integrating audience, hard message, and pressure-handling.","tips":["Frame in their terms — deals, not lines — from the first word.","Deliver the constraint clearly, then the prioritization path.","Pre-empt the 'so you're fine losing deals' pushback."],"focus":["audience","impact"]},
    {"id":"together-ops-senior-06","level":"senior","profession":"operator","title":"The recall recommendation, complete","scenario":"You're writing the full recall recommendation to the CEO: lead with the recommendation, structure the case, use precise scope, own the call, and pre-empt the cost objection. Everything integrated in one memo.","task":"Write the complete recommendation (5-6 sentences) integrating the skills.","tips":["Recommendation first, precisely scoped.","Structure: why, scope, cost, alternative considered.","Own the call and pre-empt the 'is it worth it' objection."],"focus":["structure","impact"],"placeholder":"I recommend a voluntary recall of lot 4417 — about 18,000 units, 2% likely defective."},
    {"id":"together-ops-senior-07","level":"senior","profession":"operator","title":"The KPI review, fully integrated","scenario":"You're preparing the monthly executive KPI review to run as a narrative, not a readout: one governing insight, precise numbers, your judgment on what holds, and the one decision needed. Integrate it all.","task":"Write the opening 4-5 sentences of the review, integrating structure, precision, and presence.","tips":["Open with the month's one insight, not the dashboard.","Precise numbers with your judgment on sustainability.","End on the one thing that needs a decision."],"focus":["structure","impact"]},
    {"id":"together-ops-senior-08","level":"senior","profession":"operator","title":"The vendor negotiation opener","scenario":"You're opening a major vendor negotiation with their executive team. You need audience framing (their interests), a clear structure (your priorities), presence (owning your position), and readiness for pushback — in your opening statement.","task":"Write your 4-5 sentence negotiation opening integrating the skills.","tips":["Frame the mutual case before your demands.","Structure your priorities clearly — must-haves versus tradeables.","Own your position with confidence, ready for the counter."],"focus":["audience","impact"]},
    {"id":"together-ops-senior-09","level":"senior","profession":"operator","title":"The reorganization announcement","scenario":"You're announcing the operations reorganization to the whole org. It needs a change narrative, audience-first framing, clear structure, a steady presence, and honesty about what's hard — all in a message people will screenshot.","task":"Write the full announcement (5-6 sentences) integrating narrative, audience, and hard-message skills.","tips":["Open with the why, framed for the workforce.","Clear structure: what changes, what stays, what's next.","Be honest about the disruption; steady, not falsely upbeat."],"focus":["audience","impact"]},
    {"id":"together-ops-senior-10","level":"senior","profession":"operator","title":"The earnings-call operations input","scenario":"The CEO needs your operations input for the earnings call: two sentences, analyst-calibrated, precise, defensible, leading with the point. It must survive scrutiny and be quotable. Everything compressed into two lines.","task":"Write the two-sentence earnings input integrating precision, audience, and concision.","tips":["Analyst frame: cause, magnitude, duration.","Precise and defensible — they model on your words.","Lead with the point; two sentences, no filler."],"focus":["precision","concision"],"placeholder":"We cut cost per unit 6% year over year while lifting volume 11%; ocean-freight disruption added about $9M this quarter, easing by Q3."},
    {"id":"together-ops-senior-11","level":"senior","profession":"operator","title":"The capacity ask, board-ready","scenario":"You're writing the full capacity-investment ask for the board: SCQA framing, precise numbers, an owned recommendation, and a pre-empted objection. It must be persuasive and decision-ready in under a page.","task":"Write the complete ask (5-6 sentences) integrating narrative, precision, and presence.","tips":["SCQA: the growth, the capacity gap, the decision.","Precise numbers with the payback.","Own the recommendation; pre-empt the timing objection."],"focus":["structure","impact"]},
    {"id":"together-ops-senior-12","level":"senior","profession":"operator","title":"Edit your own draft like a reader","scenario":"You've drafted the network-redesign memo and it reads fine to you because you know what it means. Now edit it as a first-time board reader would: does it lead clearly, flow logically, and land the ask?","task":"Write the two things you'd fix first in a reader's-eye edit, with the corrected sentences.","tips":["Read as someone who knows nothing — where do they get lost?","Check the lead: is the point in the first sentence?","Check the ask: is it unmistakable at the end?"],"focus":["clarity","structure"]},
    {"id":"together-ops-senior-13","level":"senior","profession":"operator","title":"The customer-CEO recovery message","scenario":"You're writing to the CEO of your largest customer after service failures: matched altitude, owned accountability, a precise commitment, and readiness for their skepticism. Executive to executive, integrated.","task":"Write the full recovery message (4-5 sentences) integrating audience, hard-message, and precision skills.","tips":["Match their altitude — outcomes, not logistics.","Own the failure, then a precise dated commitment.","Anticipate the 'you said this before' and answer it."],"focus":["audience","impact"],"placeholder":"I want to address the late shipments directly and own them."},
    {"id":"together-ops-senior-14","level":"senior","profession":"operator","title":"The all-hands after a bad quarter","scenario":"Operations had a rough quarter — missed targets, a lost customer. You address 4,000 people. You need honesty, a clear structure, a forward narrative, and steady presence, without spin or false cheer. All integrated.","task":"Write the all-hands opening (5-6 sentences) integrating honesty, structure, and narrative.","tips":["Open honest about the quarter — no spin.","Structure: where we are, why, what changes.","Forward narrative with steady presence to close."],"focus":["audience","impact"]},
    {"id":"together-ops-senior-15","level":"senior","profession":"operator","title":"The risk briefing for the audit committee","scenario":"You're briefing the audit committee on operational risk: audience-calibrated, structured into a few themes, precise on exposure, and clear on mitigation status. Their frame, your evidence, one page.","task":"Write the full briefing (5-6 sentences) integrating audience, structure, and precision.","tips":["Their frame: exposure, runway, controls.","Structure into a few ranked themes, not a register.","Precise exposure numbers with honest mitigation status."],"focus":["audience","precision"],"placeholder":"Two concentrations dominate our operational risk."},
    {"id":"together-ops-senior-16","level":"senior","profession":"operator","title":"The hallway CEO briefing","scenario":"The CEO gives you two minutes in the hallway before she walks into the board. She needs the three things that matter about operations right now, crisp and prioritized. Lead, structure, precision, presence — spoken, fast.","task":"Write the 3-4 sentence spoken briefing integrating lead, structure, and concision.","tips":["Lead with the one thing she must know.","Three points, prioritized, each a clause.","Crisp and confident — she's walking as you talk."],"focus":["concision","impact"],"placeholder":"Three things before you walk in: we hit the cost target, the recall is contained, and I need a footprint decision this month."},
    {"id":"together-ops-senior-17","level":"senior","profession":"operator","title":"The investment case Q&A","scenario":"You've presented the automation case and now face board Q&A. You must answer the questions actually asked, handle pushback with specifics, own the risks, and stay precise — integrating everything under live pressure.","task":"Write your answers to two likely tough questions (2-3 sentences each), integrating pressure and precision.","tips":["Answer the actual question first, then support.","Handle pushback with specifics, not defensiveness.","Own the risk you'd rather not raise."],"focus":["precision","impact"]},
    {"id":"together-ops-senior-18","level":"senior","profession":"operator","title":"The supplier-crisis board memo","scenario":"You're writing the board memo on the supplier bankruptcy: lead with the situation and plan, structure the exposure and mitigation, precise runway numbers, steady presence, and honest about the gap. All in one page under time pressure.","task":"Write the complete memo (5-6 sentences) integrating the skills.","tips":["Lead with what happened and that you have a plan.","Structure: exposure, runway, mitigation, gap.","Precise weeks, steady tone, honest about the risk."],"focus":["structure","precision"],"placeholder":"Our sole-source electronics supplier filed for bankruptcy; we have 11 weeks of runway and two alternates in qualification."},
    {"id":"together-ops-senior-19","level":"senior","profession":"operator","title":"The workforce automation town hall","scenario":"You're running the town hall on the automation program at the affected plant. Audience-first (their jobs), honest about cuts, a forward narrative, structured, and ready for hostile questions. The hardest integration of all.","task":"Write your opening (5-6 sentences) integrating audience, hard-message, and narrative skills.","tips":["Answer the jobs question first — it's all they hear otherwise.","Be honest about cuts within a forward narrative.","Structure it so they can follow; ready for the hard questions."],"focus":["audience","impact"]},
    {"id":"together-ops-senior-20","level":"senior","profession":"operator","title":"The one-page turnaround plan","scenario":"The CEO wants your plant-turnaround plan on one page: governing goal, three levers, precise targets, owned commitment, and the cost of not acting. Persuasive, structured, and decision-ready. Integrate everything.","task":"Write the full one-page plan (6-7 sentences) integrating structure, precision, narrative, and presence.","tips":["Governing goal and three levers up top.","Precise targets and dates for each lever.","Own the commitment; frame the cost of the status quo."],"focus":["structure","impact"]},
    {"id":"together-ops-senior-21","level":"senior","profession":"operator","title":"The layoff message, fully integrated","scenario":"You're delivering the workforce-reduction message: front-loaded bad news, audience-calibrated, structured (what, timeline, support), honest, and steady. The hardest message to get right, integrating every skill.","task":"Write the full message (5-6 sentences) integrating hard-message, audience, and structure skills.","tips":["Front-load the news; no cushioning before the fact.","Structure the support: severance, timeline, contacts.","Honest and steady — respect through clarity."],"focus":["clarity","audience"]},
    {"id":"together-ops-senior-22","level":"senior","profession":"operator","title":"The board pre-read cover note","scenario":"Your 30-page board pre-read needs a cover note that leads with the one decision, structures the sections, calibrates to directors, and cuts every wasted word. One page that makes the whole pack navigable.","task":"Write the full cover note (4-5 sentences) integrating lead, structure, and concision.","tips":["Lead with the one decision the board must make.","Structure: for-decision versus for-information, with page pointers.","Cut every word that doesn't help them navigate."],"focus":["structure","concision"],"placeholder":"One decision needs your vote this session: the footprint plan on page 12."},
    {"id":"together-ops-senior-23","level":"senior","profession":"operator","title":"The negotiation debrief and recommendation","scenario":"After round one of the logistics negotiation, you brief the exec team and recommend the next move: structured debrief, precise on the gaps, owned recommendation, and honest about the risk of walking. Integrated and decision-ready.","task":"Write the full debrief-and-recommendation (5-6 sentences) integrating structure, precision, and presence.","tips":["Structure: where we agree, the gaps, the recommendation.","Precise on the numbers still open.","Own the recommended move; name the walk-away risk."],"focus":["structure","impact"]},
    {"id":"together-ops-senior-24","level":"senior","profession":"operator","title":"The 90-second board close","scenario":"You have ninety seconds to close your operations board segment: restate the governing message, the one ask, and leave them with a clear decision. Everything you've built, landed in a strong, concise close.","task":"Write the 3-4 sentence closing integrating impact, structure, and concision.","tips":["Restate the governing message in one line.","Land the one ask unmistakably.","End on the decision, not a mumble — strong last words."],"focus":["impact","concision"],"placeholder":"To close: operations delivered the cost target and bought resilience, and the one decision in front of you is the footprint plan on page 12 — I'm asking you to approve it today."},
    {"id":"together-ops-senior-25","level":"senior","profession":"operator","title":"The COO's first strategy address","scenario":"As new COO, you deliver your first operations strategy address to the leadership team. It must integrate everything: a governing vision, clear structure, precise commitments, owned recommendations, a persuasive narrative, and the presence to lead. Your defining communication.","task":"Write the opening 6-8 sentences of the address, integrating every skill you've practiced.","tips":["Open with the vision — where you're taking operations.","Structure the strategy into memorable pillars.","Precise commitments, owned; a narrative that inspires; presence throughout."],"focus":["structure","impact"]}
  ],
};
